// Descriptions des sorts — généré automatiquement depuis aidedd.org
// Format : { desc, upcast, upcast_dice, upcast_from, save }
const SPELLS_DESC = {
  "Aide": {desc: "Votre sort emplit vos alli\u00e9s de robustesse et de r\u00e9solution. Choisissez jusqu'\u00e0 trois cr\u00e9atures \u00e0 port\u00e9e. Le maximum de points de vie et les points de vie actuels de chaque cible augmentent de 5 pour la dur\u00e9e du sort.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 3 ou sup\u00e9rieur, les points de vie de chaque cible augmentent de 5 pour chaque niveau d'emplacement au-del\u00e0 du niveau 2.", upcast_from: 2},
  "Alarme": {desc: "Vous mettez en place une alarme contre les intrusions ind\u00e9sirables. Choisissez une porte, une fen\u00eatre, ou une zone \u00e0 port\u00e9e qui ne d\u00e9passe pas un cube de 6 m\u00e8tres d'ar\u00eate. Jusqu'\u00e0 la fin du sort, une alarme vous alerte lorsqu'une cr\u00e9ature de taille TP ou sup\u00e9rieure touche ou p\u00e9n\u00e8tre la zone surveill\u00e9e. Lorsque vous lancez ce sort, vous pouvez d\u00e9signer des cr\u00e9atures qui ne d\u00e9clencheront pas l'alarme. Vous pouvez \u00e9galement choisir si l'alarme est audible ou juste mentale.Une alarme mentale vous alerte avec une sonnerie dans votre esprit \u00e0 condition que vous soyez \u00e0 1,5 km maximum de la zone s..."},
  "Animation des morts": {desc: "Ce sort cr\u00e9e un serviteur mort-vivant. Choisissez un tas d'ossements ou le cadavre d'un humano\u00efde de taille M ou P dans la port\u00e9e du sort. Votre sort insuffle un semblant de vie \u00e0 la cible pour la relever en tant que cr\u00e9ature morte-vivante. La cible devient un squelette si vous avez choisi des ossements, ou un zombi si vous avez choisi un cadavre.\u00c0 chacun de vos tours, vous pouvez utiliser une action bonus pour commander mentalement les cr\u00e9atures que vous avez anim\u00e9es avec ce sort si elles sont \u00e0 18 m\u00e8tres ou moins de vous. Si vous contr\u00f4lez plusieurs cr\u00e9atures, vous commandez simultan\u00e9ment...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 4 ou sup\u00e9rieur, vous animez ou r\u00e9affirmez votre contr\u00f4le sur deux cr\u00e9atures mortes-vivantes additionnelles pour chaque niveau d'emplacement au-del\u00e0 du niveau 3. Chaque cr\u00e9ature doit provenir d'un cadavre ou d'un tas d'ossements diff\u00e9rent.", upcast_from: 3},
  "Apaisement des \u00e9motions": {desc: "Vous tentez de supprimer les \u00e9motions fortes dans un groupe de personnes. Chaque humano\u00efde dans une sph\u00e8re de 6 m\u00e8tres de rayon centr\u00e9e sur un point choisi dans la port\u00e9e du sort doit effectuer un jet de sauvegarde de Charisme. Une cr\u00e9ature peut choisir de rater volontairement son jet de sauvegarde. En cas d'\u00e9chec au jet de sauvegarde, choisissez l'un des deux effets suivants.Vous pouvez supprimer tous les effets qui font qu'une cible est charm\u00e9e ou effray\u00e9e. Lorsque ce sort prend fin, les effets supprim\u00e9s reviennent, en pr\u00e9sumant que leur dur\u00e9e n'a pas expir\u00e9 entre temps.Ou vous pouvez ren...", save: "CHA"},
  "Appel de la foudre": {desc: "Un nuage d'orage prend la forme d'un cylindre de 3 m\u00e8tres de hauteur et d'un rayon de 18 m\u00e8tres centr\u00e9 sur un point visible \u00e0 port\u00e9e au-dessus de vous. Le sort \u00e9choue si vous ne pouvez voir un point en l'air l\u00e0 o\u00f9 le nuage devrait appara\u00eetre (par exemple, si vous vous trouvez dans une pi\u00e8ce trop petite pour accueillir le nuage).Lorsque vous incantez le sort, choisissez un point visible sous le nuage. Un \u00e9clair jaillit du nuage jusqu'au point choisi. Chaque cr\u00e9ature \u00e0 1,50 m\u00e8tre ou moins de ce point doit effectuer un jet de sauvegarde de Dext\u00e9rit\u00e9, subissant 3d10 d\u00e9g\u00e2ts de foudre en cas d'\u00e9c...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 4 ou sup\u00e9rieur, les d\u00e9g\u00e2ts augmentent de 1d10 pour chaque niveau d'emplacement au-del\u00e0 du niveau 3.", upcast_dice: "1d10", upcast_from: 3, save: "DEX"},
  "Arme magique": {desc: "Vous touchez une arme non magique. Jusqu'\u00e0 la fin du sort, l'arme est consid\u00e9r\u00e9e comme \u00e9tant une arme magique avec un bonus de +1 aux jets d'attaque et aux d\u00e9g\u00e2ts.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 4 ou sup\u00e9rieur, le bonus augmente \u00e0 +2. Lorsque vous utilisez un emplacement de sort de niveau 6 ou sup\u00e9rieur, le bonus augmente \u00e0 +3.", upcast_from: 4},
  "Arr\u00eat du temps": {desc: "Vous arr\u00eatez bri\u00e8vement l'\u00e9coulement du temps pour tout le monde, sauf pour vous-m\u00eame. Le temps ne s'\u00e9coule pas pour les autres cr\u00e9atures, tandis que vous profitez de 1d4 + 1 tours au cours desquels vous pouvez utiliser \u00e0 votre guise les actions et mouvements qui vous sont dus normalement.Ce sort prend fin si l'une des actions que vous utilisez lors de cette p\u00e9riode, ou l'un des effets que vous cr\u00e9ez au cours de cette p\u00e9riode, affecte une cr\u00e9ature autre que vous ou un objet \u00e9tant port\u00e9 par quelqu'un d'autre que vous. De plus, le sort prend fin si vous vous d\u00e9placez \u00e0 plus de 300 m\u00e8tres d'o\u00f9..."},
  "Aspersion acide": {desc: "Vous propulsez une bulle d'acide. Choisissez une ou deux cr\u00e9atures que vous pouvez voir, \u00e0 1,50 m\u00e8tre ou moins l'une de l'autre, dans la port\u00e9e du sort. La cible doit r\u00e9ussir un jet de sauvegarde de Dext\u00e9rit\u00e9 ou subir 1d6 d\u00e9g\u00e2ts d'acide.Les d\u00e9g\u00e2ts de ce sort augmentent de 1d6 lorsque vous atteignez le niveau 5 (2d6), le niveau 11 (3d6) et le niveau 17 (4d6).", save: "DEX"},
  "Baies nourrici\u00e8res": {desc: "Jusqu'\u00e0 dix baies impr\u00e9gn\u00e9es de magie apparaissent dans votre main pour la dur\u00e9e de leur potentiel (voir ci-dessous). Une cr\u00e9ature peut utiliser son action pour manger une baie. Manger une baie rend 1 point de vie, et la baie est suffisamment nourrissante pour sustenter une cr\u00e9ature pour une journ\u00e9e.Les baies perdent leur potentiel si elles n'ont pas \u00e9t\u00e9 consomm\u00e9es dans les 24 heures qui suivent le lancement du sort."},
  "Bouche magique": {desc: "Vous implantez un message dans un objet dans la port\u00e9e du sort. Le message est verbalis\u00e9 lorsque les conditions de d\u00e9clenchement sont remplies. Choisissez un objet que vous voyez et qui n'est pas port\u00e9 ou transport\u00e9 par une autre cr\u00e9ature. Ensuite, prononcez le message, qui ne doit pas d\u00e9passer 25 mots mais dont l'\u00e9coute peut prendre jusqu'\u00e0 10 minutes. Finalement, \u00e9tablissez les circonstances qui d\u00e9clencheront le sort pour livrer votre message.Lorsque ces circonstances sont r\u00e9unies, une bouche magique appara\u00eet sur l'objet et elle articule le message en imitant votre voix, sur le m\u00eame ton e..."},
  "Bouclier": {desc: "Une barri\u00e8re invisible de force magique appara\u00eet et vous prot\u00e8ge. Jusqu'au d\u00e9but de votre prochain tour, vous obtenez un bonus de +5 \u00e0 votre CA, y compris contre l'attaque qui a d\u00e9clench\u00e9 le sort, et vous ne prenez aucun d\u00e9g\u00e2t par le sort projectile magique."},
  "Bouclier de la foi": {desc: "Un champ scintillant appara\u00eet et entoure une cr\u00e9ature de votre choix dans la port\u00e9e du sort, lui accordant un bonus de +2 \u00e0 la CA pour la dur\u00e9e du sort."},
  "Bouff\u00e9e de poison": {desc: "Vous tendez votre paume vers une cr\u00e9ature visible dans la port\u00e9e du sort et vous projetez une bouff\u00e9e de gaz nocif de votre main. La cr\u00e9ature doit r\u00e9ussir un jet de sauvegarde de Constitution ou subir 1d12 d\u00e9g\u00e2ts de poison.Les d\u00e9g\u00e2ts de ce sort augmentent de 1d12 lorsque vous atteignez le niveau 5 (2d12), le niveau 11 (3d12) et le niveau 17 (4d12).", save: "CON"},
  "Boule de feu": {desc: "Une \u00e9clatante tra\u00een\u00e9e lumineuse est \u00e9mise de la pointe de votre doigt vers un point de votre choix dans la port\u00e9e du sort, puis s'amplifie dans un rugissement grave jusqu'\u00e0 \u00e9clater en flammes. Chaque cr\u00e9ature situ\u00e9e dans une sph\u00e8re de 6 m\u00e8tres de rayon centr\u00e9e sur le point doit effectuer un jet de sauvegarde de Dext\u00e9rit\u00e9, subissant 8d6 d\u00e9g\u00e2ts de feu en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite.Le feu contourne les coins. Il enflamme les objets inflammables qui ne sont pas port\u00e9s ou transport\u00e9s.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 4 ou sup\u00e9rieur, les d\u00e9g\u00e2ts sont augment\u00e9s de 1d6 pour chaque niveau d'emplacement au-del\u00e0 du niveau 3.", upcast_dice: "1d6", upcast_from: 3, save: "DEX"},
  "B\u00e9n\u00e9diction": {desc: "Vous b\u00e9nissez jusqu'\u00e0 trois cr\u00e9atures de votre choix, dans la port\u00e9e du sort. \u00c0 chaque fois qu'une cible fait un jet d'attaque ou de sauvegarde avant la fin du sort, la cible peut lancer un d4 et ajouter le r\u00e9sultat au jet d'attaque ou de sauvegarde.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, vous pouvez cibler une cr\u00e9ature suppl\u00e9mentaire pour chaque niveau d'emplacement au-del\u00e0 du niveau 1.", upcast_from: 1},
  "Cage de force": {desc: "Une prison en forme de cube immobile et invisible, compos\u00e9e de force magique, appara\u00eet autour d'une zone que vous choisissez et \u00e0 port\u00e9e. La prison peut \u00eatre une cage ou une bo\u00eete solide, selon votre choix.Une prison prenant la forme d'une cage peut faire jusqu'\u00e0 6 m\u00e8tres de c\u00f4t\u00e9 et est constitu\u00e9e de barreaux de 1,25 cm de diam\u00e8tre et espac\u00e9s de 1,25 cm \u00e9galement.Une prison prenant la forme d'une bo\u00eete peut faire jusqu'\u00e0 3 m\u00e8tres de c\u00f4t\u00e9, cr\u00e9ant une barri\u00e8re solide qui emp\u00eache la mati\u00e8re de passer au travers et bloque les sorts lanc\u00e9s de l'int\u00e9rieur vers l'ext\u00e9rieur de la zone, et vice vers...", save: "CHA"},
  "Cercle de mort": {desc: "Une sph\u00e8re d'\u00e9nergie n\u00e9gative s'\u00e9tend dans un rayon de 18 m\u00e8tres \u00e0 partir d'un point \u00e0 port\u00e9e. Chaque cr\u00e9ature pr\u00e9sente dans la zone doit effectuer un jet de sauvegarde de Constitution, subissant 8d6 d\u00e9g\u00e2ts n\u00e9crotiques en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 7 ou sup\u00e9rieur, les d\u00e9g\u00e2ts augmentent de 2d6 pour chaque niveau d'emplacement au-del\u00e0 du niveau 6.", upcast_dice: "2d6", upcast_from: 6, save: "CON"},
  "Cercle magique": {desc: "Vous cr\u00e9ez un cylindre d'\u00e9nergie magique haut de 6 m\u00e8tres et d'un rayon de 3 m\u00e8tres, centr\u00e9 sur un point du sol que vous pouvez voir et \u00e0 port\u00e9e. Des runes rayonnantes apparaissent aux endroits o\u00f9 le cylindre s'intersecte avec le sol, ou toute autre surface.Choisissez un ou plusieurs types de cr\u00e9atures parmi les suivants : c\u00e9leste, \u00e9l\u00e9mentaire, f\u00e9e, fi\u00e9lon ou mort-vivant. Le cercle affecte une cr\u00e9ature d'un type choisi des mani\u00e8res suivantes :\u2022 La cr\u00e9ature ne peut volontairement p\u00e9n\u00e9trer dans le cylindre par des moyens non magiques. Si la cr\u00e9ature tente d'utiliser la t\u00e9l\u00e9portation ou le voy...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort niveau 4 ou sup\u00e9rieur, la dur\u00e9e augmente de 1 heure pour chaque niveau d'emplacement au-del\u00e0 du niveau 3.", upcast_from: 3, save: "CHA"},
  "Changement de plan": {desc: "Vous et jusqu'\u00e0 huit cr\u00e9atures consentantes qui vous tenez par les mains en formant un cercle, \u00eates transport\u00e9s dans un plan d'existence diff\u00e9rent. Vous pouvez sp\u00e9cifier une destination en termes g\u00e9n\u00e9raux, comme la Cit\u00e9 d'Airain dans le plan \u00e9l\u00e9mentaire du feu ou le palace de Dispater au deuxi\u00e8me niveau des Neuf enfers, et vous apparaissez dans, ou \u00e0 proximit\u00e9 de votre destination. Si vous essayez d'atteindre la Cit\u00e9 d'Airain par exemple, vous pourriez arriver dans la rue du M\u00e9tal, devant ses Portes de cendres, ou regardant la cit\u00e9 depuis l'autre c\u00f4t\u00e9 de la Mer de feu, \u00e0 la discr\u00e9tion du MD...", save: "CHA"},
  "Charme-personne": {desc: "Vous pouvez tenter de charmer un humano\u00efde que vous pouvez voir \u00e0 port\u00e9e. Ce dernier doit effectuer un jet de sauvegarde de Sagesse, avec un avantage \u00e0 son jet si vous ou vos compagnons le combattez. En cas d'\u00e9chec, il est charm\u00e9 jusqu'\u00e0 la fin de la dur\u00e9e du sort ou jusqu'\u00e0 ce que vous ou vos compagnons cherchiez \u00e0 lui nuire. La cr\u00e9ature charm\u00e9e vous consid\u00e8re comme un bon ami. Quand le sort prend fin, la cr\u00e9ature sait que vous l'avez charm\u00e9e.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, vous pouvez cibler une cr\u00e9ature suppl\u00e9mentaire pour chaque niveau d'emplacement au-del\u00e0 du niveau 1. Les cr\u00e9atures doivent se trouver \u00e0 9 m\u00e8tres maximum les unes des autres lorsque vous les ciblez.", upcast_from: 1, save: "WIS"},
  "Ch\u00e2timent courrouc\u00e9": {desc: "La prochaine fois que vous touchez une cible lors d'une attaque au corps \u00e0 corps avec une arme pendant la dur\u00e9e du sort, votre attaque inflige 1d6 d\u00e9g\u00e2ts psychiques suppl\u00e9mentaires. De plus, si la cible est une cr\u00e9ature, elle doit r\u00e9ussir un jet de sauvegarde de Sagesse ou \u00eatre effray\u00e9e jusqu'\u00e0 la fin du sort. Par une action, la cr\u00e9ature peut effectuer un jet de Sagesse contre le DD de sauvegarde de votre sort pour mettre un terme \u00e0 cet effet et au sort.", save: "WIS"},
  "Ch\u00e2timent r\u00e9v\u00e9lateur": {desc: "La prochaine fois que vous touchez une cr\u00e9ature lors d'une attaque avec une arme avant que le sort ne prenne fin, votre arme rayonne d'une lueur astrale au moment de l'impact. L'attaque inflige 2d6 d\u00e9g\u00e2ts radiants suppl\u00e9mentaires \u00e0 la cible, qui devient visible si elle \u00e9tait invisible, et la cible \u00e9met une lumi\u00e8re faible dans un rayon de 1,50 m\u00e8tre et ne peut devenir invisible tant que le sort persiste.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 3 ou sup\u00e9rieur, les d\u00e9g\u00e2ts suppl\u00e9mentaires augmentent de 1d6 pour chaque niveau d'emplacement au-del\u00e0 du niveau 2.", upcast_dice: "1d6", upcast_from: 2},
  "Clairvoyance": {desc: "Vous cr\u00e9ez un d\u00e9tecteur invisible, \u00e0 port\u00e9e, dans une zone qui vous est famili\u00e8re (un endroit que vous avez visit\u00e9 ou d\u00e9j\u00e0 vu) ou dans une zone \u00e9vidente qui ne vous est pas famili\u00e8re (comme l'autre c\u00f4t\u00e9 d'une porte, derri\u00e8re un angle ou dans un bosquet). Le d\u00e9tecteur reste en place pour la dur\u00e9e du sort, il ne peut pas \u00eatre attaqu\u00e9 ou \u00eatre en interaction avec quoi que ce soit.Lorsque vous lancez le sort, vous choisissez de voir ou d'entendre. Vous pouvez utiliser le sens choisi au travers du d\u00e9tecteur comme si vous \u00e9tiez \u00e0 sa place. En utilisant votre action, vous pouvez alterner entre la v..."},
  "Clone": {desc: "Ce sort cr\u00e9e le double inerte d'une cr\u00e9ature vivante, servant de protection contre la mort. Ce clone se forme \u00e0 l'int\u00e9rieur du r\u00e9cipient utilis\u00e9 par le sort et atteint sa taille maximale et sa maturit\u00e9 au bout de 120 jours ; vous pouvez \u00e9galement choisir d'avoir un clone d'une version plus jeune de la m\u00eame cr\u00e9ature. Ce clone reste inerte et persiste ind\u00e9finiment, tant que son contenant n'est pas d\u00e9rang\u00e9.\u00c0 n'importe quel moment, une fois le clone mature, si la cr\u00e9ature originale meurt, son \u00e2me est transf\u00e9r\u00e9e dans le clone, \u00e0 condition que l'\u00e2me soit libre et qu'elle soit consentante \u00e0 son re..."},
  "Communication avec les morts": {desc: "Vous accordez un semblant de vie et d'intelligence \u00e0 un cadavre de votre choix dans la port\u00e9e du sort, ce qui lui permet de r\u00e9pondre aux questions que vous lui posez. Le cadavre doit encore avoir une bouche et ne peut pas \u00eatre un mort-vivant. Le sort \u00e9choue si le cadavre a \u00e9t\u00e9 la cible de ce sort durant les 10 derniers jours.Jusqu'\u00e0 ce que le sort se termine, vous pouvez poser cinq questions au cadavre. Le cadavre ne conna\u00eet que ce qu'il savait durant son vivant, y compris les langues. Les r\u00e9ponses sont g\u00e9n\u00e9ralement br\u00e8ves, \u00e9nigmatiques ou r\u00e9p\u00e9titives, et le cadavre n'est pas oblig\u00e9 de donn..."},
  "Compr\u00e9hension des langues": {desc: "Pendant la dur\u00e9e du sort, vous comprenez la signification litt\u00e9rale de toute langue parl\u00e9e que vous pouvez entendre. Vous comprenez \u00e9galement tout langage \u00e9crit que vous pouvez voir, mais vous devez toucher la surface sur laquelle les mots sont inscrits. Il faut une minute pour lire une page de texte.Ce sort ne d\u00e9code pas les messages secrets dans un texte ou un glyphe, tel qu'un symbole magique, qui ne fait pas partie du langage \u00e9crit."},
  "Confusion": {desc: "Ce sort assaille et tord les esprits des cr\u00e9atures, g\u00e9n\u00e9rant des illusions et provoquant des actions incontr\u00f4l\u00e9es. Chaque cr\u00e9ature dans une sph\u00e8re de 3 m\u00e8tres de rayon centr\u00e9e sur un point choisi dans la port\u00e9e du sort doit r\u00e9ussir un jet de sauvegarde de Sagesse, sans quoi elle sera affect\u00e9e par le sort.Une cible affect\u00e9e ne peut r\u00e9agir et elle doit lancer 1d10 au d\u00e9but de chacun de ses tours pour d\u00e9terminer son comportement pour ce tour.d10Comportement1La cr\u00e9ature emploie tout son mouvement pour se d\u00e9placer de fa\u00e7on al\u00e9atoire. Pour d\u00e9terminer la direction, lancez 1d8 et assignez une direc...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 5 ou sup\u00e9rieur, le rayon de la sph\u00e8re augmente de 1,50 m\u00e8tre pour chaque niveau d'emplacement au-del\u00e0 du niveau 4.", upcast_from: 4, save: "WIS"},
  "Contact glacial": {desc: "Vous cr\u00e9ez une main squelettique fantomatique dans l'espace d'une cr\u00e9ature \u00e0 port\u00e9e. Faites une attaque \u00e0 distance avec un sort contre la cr\u00e9ature pour l'\u00e9treindre d'une froideur s\u00e9pulcrale. Si le coup touche, la cible subit 1d8 d\u00e9g\u00e2ts n\u00e9crotiques, et elle ne peut r\u00e9cup\u00e9rer ses points de vie avant le d\u00e9but de votre prochain tour. Jusque-l\u00e0, la main fantomatique s'accroche \u00e0 la cible. Si vous ciblez un mort-vivant, il aura \u00e9galement un d\u00e9savantage \u00e0 ses jets d'attaque contre vous jusqu'\u00e0 la fin de votre prochain tour.Les d\u00e9g\u00e2ts de ce sort augmentent de 1d8 lorsque vous atteignez le niveau 5 ..."},
  "Contamination": {desc: "Vous lib\u00e9rez une infection virulente sur une cr\u00e9ature que vous voyez dans la port\u00e9e du sort. La cible doit effectuer un jet de sauvegarde de Constitution, subissant 14d6 d\u00e9g\u00e2ts n\u00e9crotiques en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite. Les d\u00e9g\u00e2ts ne peuvent r\u00e9duire les points de vie de la cible sous 1. Si la cible \u00e9choue le jet de sauvegarde, son maximum de points de vie est amput\u00e9 pour 1 heure de la m\u00eame quantit\u00e9 de d\u00e9g\u00e2ts n\u00e9crotiques subis. Tout effet qui enraye la maladie permet au maximum de points de vie de la cr\u00e9ature de retrouver sa valeur normale avant la fin de l'ef...", save: "CON"},
  "Contresort": {desc: "Vous tentez d'interrompre une cr\u00e9ature au moment o\u00f9 elle incante un sort. Si la cr\u00e9ature incante un sort de niveau 3 ou inf\u00e9rieur, son sort \u00e9choue et il n'a aucun effet. Si elle incante un sort de niveau 4 ou sup\u00e9rieur, effectuez un jet de caract\u00e9ristique selon celle qui sert \u00e0 lancer vos sorts. Le DD est de 10 + le niveau du sort. En cas de r\u00e9ussite, le sort de la cr\u00e9ature \u00e9choue et il n'a aucun effet.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 4 ou sup\u00e9rieur, le sort interrompu n'a aucun effet si son niveau est inf\u00e9rieur ou \u00e9gal \u00e0 celui du niveau de l'emplacement de sort utilis\u00e9.", upcast_from: 4},
  "Contr\u00f4le de l'eau": {desc: "Jusqu'\u00e0 la fin du sort, vous contr\u00f4lez toute \u00e9tendue d'eau libre dans une zone cubique de 30 m\u00e8tres d'ar\u00eate de votre choix. Vous pouvez choisir parmi les effets suivants lors de l'incantation du sort. Par une action, durant votre tour, vous pouvez r\u00e9p\u00e9ter le m\u00eame effet ou en choisir un nouveau.Crue. Vous provoquez l'augmentation de 6 m\u00e8tres du niveau de toute l'eau pr\u00e9sente dans la zone d'effet. Si la zone d'effet comprend une berge, l'eau se d\u00e9verse sur le sol sec. Si votre zone d'effet se trouve au sein d'une importante \u00e9tendue d'eau, vous cr\u00e9ez plut\u00f4t une vague de 6 m\u00e8tres de haut qui pa...", save: "STR"},
  "Contr\u00f4le des vents": {desc: "Vous prenez le contr\u00f4le de l'air dans un cube de 30 m\u00e8tres d'ar\u00eate visible dans la port\u00e9e du sort. Vous pouvez choisir un des effets suivants lorsque vous lancez le sort. L'effet perdure jusqu'\u00e0 la fin du sort, \u00e0 moins que vous n'utilisiez votre action au cour d'un tour ult\u00e9rieur pour changer d'effet. Vous pouvez aussi utiliser votre action pour momentan\u00e9ment arr\u00eater l'effet ou pour renouveler un effet que vous auriez arr\u00eat\u00e9.Rafales. Un vent se l\u00e8ve au centre du cube et souffle continuellement dans une direction horizontale que vous choisissez. Vous pouvez d\u00e9cider de l'intensit\u00e9 du vent : c...", save: "STR"},
  "Convocation de d\u00e9mons mineurs": {desc: "Vous prononcez des mots vulgaires, invoquant des d\u00e9mons du chaos des Abysses. Jetez un d\u00e9 sur la table suivante pour d\u00e9terminer ce qui appara\u00eet.d6D\u00e9mons invoqu\u00e9s1-2Deux d\u00e9mons de FP 1 ou moins3-4Quatre d\u00e9mons de FP 1/2 ou moins5-6Huit d\u00e9mons de FP 1/4 ou moinsLe MD choisit les d\u00e9mons, comme les m\u00e2nes ou les dretchs, et vous choisissez les espaces inoccup\u00e9s que vous pouvez voir \u00e0 port\u00e9e o\u00f9 ils apparaissent. Un d\u00e9mon invoqu\u00e9 dispara\u00eet lorsqu'il tombe \u00e0 0 point de vie ou lorsque le sort se termine.Les d\u00e9mons sont hostiles \u00e0 toutes les cr\u00e9atures, vous y compris. Lancez l'initiative pour le grou...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 6 ou 7, vous invoquez deux fois plus de d\u00e9mons. Si vous le lancez en utilisant un emplacement de sort de niveau 8 ou 9, vous invoquez trois fois plus de d\u00e9mons."},
  "Corde enchant\u00e9e": {desc: "Vous touchez une longueur de corde de 18 m\u00e8tres maximum. Une extr\u00e9mit\u00e9 de la corde se dresse alors et monte dans les airs de sorte que toute la longueur de la corde soit verticale par rapport au sol. \u00c0 l'extr\u00e9mit\u00e9 sup\u00e9rieure de la corde, une entr\u00e9e invisible vers un espace extradimensionnel s'ouvre et reste en place pour toute la dur\u00e9e du sort.L'espace extradimensionnel peut \u00eatre atteint en grimpant tout en haut de la corde. L'espace peut contenir jusqu'\u00e0 huit cr\u00e9atures de taille M ou inf\u00e9rieure. La corde peut \u00eatre tir\u00e9e dans l'espace extradimensionnel, elle dispara\u00eet alors de la vue de ceu..."},
  "Coup au but": {desc: "Vous tendez votre main et pointez un doigt en direction d'une cible \u00e0 port\u00e9e. Votre magie vous aide \u00e0 trouver une petite faille dans les d\u00e9fenses de votre cible. Lors de votre prochain tour, vous obtenez un avantage pour votre premier jet d'attaque contre la cible, \u00e0 condition que le sort ne soit pas d\u00e9j\u00e0 termin\u00e9."},
  "Coup de tonnerre": {desc: "Vous cr\u00e9ez un bruit de tonnerre qui peut \u00eatre entendu jusqu'\u00e0 30 m\u00e8tres. Hormis vous-m\u00eame, toute cr\u00e9ature \u00e0 port\u00e9e doit r\u00e9ussir un jet de sauvegarde de Constitution ou subir 1d6 d\u00e9g\u00e2ts de tonnerre.Les d\u00e9g\u00e2ts de ce sort augmentent de 1d6 lorsque vous atteignez le niveau 5 (2d6), le niveau 11 (3d6) et le niveau 17 (4d6).", save: "CON"},
  "Couverture de neige": {desc: "Vous cr\u00e9ez une sph\u00e8re de brouillard de 6 m\u00e8tres de rayon centr\u00e9e sur un point dans la port\u00e9e du sort. La sph\u00e8re s'\u00e9tend au-del\u00e0 des coins et la visibilit\u00e9 dans la zone est nulle. Elle persiste pour la dur\u00e9e du sort ou jusqu'\u00e0 ce qu'un vent de force mod\u00e9r\u00e9e ou plus (au moins 15 km/h) la dissipe.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, le rayon de la sph\u00e8re augmente de 6 m\u00e8tres pour chaque niveau d'emplacement au-del\u00e0 du niveau 1.", upcast_from: 1},
  "Croissance v\u00e9g\u00e9tale": {desc: "Ce sort canalise une force vitale vers les plantes pr\u00e9sentes dans une zone sp\u00e9cifique. Il y a deux usages possibles du sort. L'un procure des b\u00e9n\u00e9fices imm\u00e9diats alors que l'autre s'\u00e9tale sur un plus long terme.Si vous lancez ce sort en utilisant 1 action, choisissez un point dans la port\u00e9e du sort. Toutes plantes normales pr\u00e9sentes dans un rayon de 30 m\u00e8tres autour de ce point croissent avec vigueur. Une cr\u00e9ature se d\u00e9pla\u00e7ant \u00e0 travers la zone doit consommer 4 m\u00e8tres de mouvement pour parcourir 1 m\u00e8tre.Vous pouvez d\u00e9signer une ou plusieurs zones de dimension variable comme \u00e9tant exclues de..."},
  "Cr\u00e9ation de mort-vivant": {desc: "Vous ne pouvez lancer ce sort que durant la nuit. Choisissez jusqu'\u00e0 trois cadavres d'humano\u00efdes de taille M ou P \u00e0 port\u00e9e. Chaque cadavre devient une goule sous votre contr\u00f4le.Par une action bonus, \u00e0 chacun de vos tours, vous pouvez mentalement donner des ordres \u00e0 toute cr\u00e9ature que vous avez anim\u00e9e avec ce sort, si elle se trouve \u00e0 36 m\u00e8tres ou moins de vous (si vous contr\u00f4lez de nombreuses cr\u00e9atures, vous pouvez donner vos ordres \u00e0 plusieurs d'entre elles, voire \u00e0 toutes, en m\u00eame temps, \u00e0 condition qu'elles re\u00e7oivent toutes le m\u00eame ordre). Vous d\u00e9cidez quelle action la cr\u00e9ature va effect...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 7, vous pouvez animer ou r\u00e9affirmer votre contr\u00f4le sur quatre goules. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 8, vous pouvez animer ou r\u00e9affirmer votre contr\u00f4le sur cinq goules ou deux bl\u00eames ou deux n\u00e9crophages. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 9, vous pouvez animer ou r\u00e9affirmer votre contr\u00f4le sur six goules ou trois bl\u00eames ou trois n\u00e9crophages ou deux momies."},
  "Cr\u00e9ation de nourriture et d'eau": {desc: "Vous cr\u00e9ez 22,5 kg de nourriture et 120 litres d'eau sur le sol ou dans des contenants, \u00e0 port\u00e9e, ce qui est assez pour subvenir aux besoins de quinze humano\u00efdes ou de cinq montures pour 24 heures. La nourriture est fade mais nourrissante, et se g\u00e2te si elle n'est pas mang\u00e9e au-del\u00e0 de 24 heures. L'eau est claire et ne croupit pas."},
  "C\u00e9cit\u00e9/Surdit\u00e9": {desc: "Vous pouvez aveugler ou assourdir un ennemi. Choisissez une cr\u00e9ature que vous pouvez voir dans la port\u00e9e du sort. Celle-ci doit r\u00e9ussir un jet de sauvegarde de Constitution sans quoi elle est soit aveugl\u00e9e, soit assourdie (selon votre choix) pour la dur\u00e9e du sort. \u00c0 la fin de chacun de ses tours, la cible effectue un jet de sauvegarde de Constitution. En cas de r\u00e9ussite, le sort prend fin.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 3 ou sup\u00e9rieur, vous pouvez cibler une cr\u00e9ature suppl\u00e9mentaire pour chaque niveau d'emplacement au-del\u00e0 du niveau 2.", upcast_from: 2, save: "CON"},
  "C\u00f4ne de froid": {desc: "Un souffle d'air froid est propuls\u00e9 de vos mains. Chaque cr\u00e9ature se trouvant dans les 18 m\u00e8tres du c\u00f4ne doit effectuer un jet de sauvegarde de Constitution. Une cr\u00e9ature subit 8d8 d\u00e9g\u00e2ts de froid en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite. Une cr\u00e9ature tu\u00e9e par le sort devient une statue de glace jusqu'\u00e0 son d\u00e9gel.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 6 ou sup\u00e9rieur, les d\u00e9g\u00e2ts augmentent de 1d8 pour chaque niveau d'emplacement au-del\u00e0 du niveau 5.", upcast_dice: "1d8", upcast_from: 5, save: "CON"},
  "Dissipation de la magie": {desc: "Choisissez une cr\u00e9ature, un objet ou un effet magique dans la port\u00e9e du sort. Tous les sorts actifs de niveau 3 ou moins sur la cible prennent fin. Pour chaque sort actif de niveau 4 ou plus sur la cible, effectuez un jet de votre caract\u00e9ristique d'incantation. Le DD est de 10 + le niveau du sort. Si le jet est r\u00e9ussi, le sort prend fin.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 4 ou sup\u00e9rieur, les effets d'un sort actif sur la cible prennent automatiquement fin si le niveau du sort est \u00e9gal ou inf\u00e9rieur au niveau de l'emplacement de sort utilis\u00e9.", upcast_from: 4},
  "Dissipation du mal et du bien": {desc: "Une \u00e9nergie chatoyante vous enveloppe et vous prot\u00e8ge des f\u00e9es, des morts-vivants et des cr\u00e9atures originaires d'autres plans que le plan mat\u00e9riel. Pour la dur\u00e9e du sort, les c\u00e9lestes, \u00e9l\u00e9mentaires, f\u00e9es, fi\u00e9lons et morts-vivants ont un d\u00e9savantage aux jets d'attaque contre vous.Vous pouvez mettre fin pr\u00e9matur\u00e9ment au sort en utilisant l'une ou l'autre des options suivantes.Annulation d'enchantement. Par une action, vous touchez une cr\u00e9ature \u00e0 port\u00e9e qui est charm\u00e9e, effray\u00e9e ou poss\u00e9d\u00e9e par un c\u00e9leste, un \u00e9l\u00e9mentaire, une f\u00e9e, un fi\u00e9lon ou un mort-vivant. La cr\u00e9ature que vous touchez cesse...", save: "CHA"},
  "Doigt de mort": {desc: "Vous envoyez de l'\u00e9nergie n\u00e9gative \u00e0 travers une cr\u00e9ature visible dans la port\u00e9e du sort, lui causant d'affreuses souffrances. La cible doit effectuer un jet de sauvegarde de Constitution, subissant 7d8 + 30 d\u00e9g\u00e2ts n\u00e9crotiques en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite.Un humano\u00efde tu\u00e9 par ce sort se rel\u00e8ve au d\u00e9but de votre prochain tour, comme un zombi que vous commandez en permanence et qui suit vos ordres verbaux au mieux de sa capacit\u00e9.", save: "CON"},
  "Domination de monstre": {desc: "Vous tentez de subjuguer une cr\u00e9ature \u00e0 port\u00e9e que vous pouvez voir. Elle doit r\u00e9ussir un jet de sauvegarde de Sagesse ou \u00eatre charm\u00e9e pour la dur\u00e9e du sort. Si vous ou des cr\u00e9atures qui vous sont amies la combattez, elle b\u00e9n\u00e9ficie d'un avantage \u00e0 son jet de sauvegarde.Tant que la cr\u00e9ature est charm\u00e9e, vous \u00e9tablissez un contact t\u00e9l\u00e9pathique avec elle aussi longtemps que vous vous trouvez tous les deux sur le m\u00eame plan d'existence. Vous pouvez utiliser ce lien t\u00e9l\u00e9pathique pour donner des ordres \u00e0 la cr\u00e9ature tant que vous \u00eates conscient (aucune action n'est requise). La cr\u00e9ature fait tout ...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 9, la dur\u00e9e du sort sous concentration augmente jusqu'\u00e0 8 heures.", save: "WIS"},
  "Domination de personne": {desc: "Vous tentez de subjuguer un humano\u00efde \u00e0 port\u00e9e que vous pouvez voir. Celui-ci doit r\u00e9ussir un jet de sauvegarde de Sagesse ou \u00eatre charm\u00e9 pour la dur\u00e9e du sort. Si vous ou des cr\u00e9atures qui vous sont amies le combattez, il b\u00e9n\u00e9ficie d'un avantage \u00e0 son jet de sauvegarde.Tant que la cible est charm\u00e9e, vous \u00e9tablissez un contact t\u00e9l\u00e9pathique avec elle aussi longtemps que vous vous trouvez tous les deux sur le m\u00eame plan d'existence. Vous pouvez utiliser ce lien t\u00e9l\u00e9pathique pour donner des ordres \u00e0 la cr\u00e9ature, tant que vous \u00eates conscient (aucune action n'est requise). La cr\u00e9ature fait tout c...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 6, la dur\u00e9e du sort sous concentration augmente jusqu'\u00e0 10 minutes. Avec un emplacement de sort de niveau 7, la dur\u00e9e du sort sous concentration augmente jusqu'\u00e0 1 heure. Avec un emplacement de sort de niveau 8 ou sup\u00e9rieur, la dur\u00e9e du sort sous concentration augmente jusqu'\u00e0 8 heures.", upcast_from: 8, save: "WIS"},
  "Druidisme": {desc: "En murmurant aux esprits de la nature, vous cr\u00e9ez l'un des effets suivants, dans la port\u00e9e du sort :\u2022 Vous cr\u00e9ez un minuscule et inoffensif effet sensoriel qui permet de pr\u00e9dire les conditions m\u00e9t\u00e9orologiques pour les 24 prochaines heures, \u00e0 l'endroit o\u00f9 vous \u00eates. L'effet pourrait se manifester comme un orbe dor\u00e9 pour indiquer un ciel d\u00e9gag\u00e9, un nuage pour annoncer la pluie, un flocon de neige pour une chute de neige et ainsi de suite. L'effet persiste pour 1 round.\u2022 Vous provoquez imm\u00e9diatement la floraison d'une fleur, l'ouverture d'une gousse ou le d\u00e9bourrement d'un bourgeon de feuille...."},
  "D\u00e9charge occulte": {desc: "Un rayon d'\u00e9nergie cr\u00e9pitante zigzague jusqu'\u00e0 une cr\u00e9ature \u00e0 port\u00e9e. Effectuez une attaque \u00e0 distance avec un sort contre la cible. En cas de r\u00e9ussite, la cible subit 1d10 d\u00e9g\u00e2ts de force.Ce sort cr\u00e9e plus d'un rayon lorsque vous montez en niveau : deux rayons au niveau 5, trois rayons au niveau 11, et quatre rayons au niveau 17. Vous pouvez diriger les rayons sur une cible unique et les r\u00e9partir entre diff\u00e9rentes cr\u00e9atures. Effectuez un jet d'attaque s\u00e9par\u00e9 pour chaque rayon."},
  "D\u00e9sint\u00e9gration": {desc: "Un mince faisceau de lumi\u00e8re verte surgit de la pointe de votre doigt vers une cible visible dans la port\u00e9e du sort. La cible peut \u00eatre une cr\u00e9ature, un objet ou une cr\u00e9ation de force magique, comme un mur fa\u00e7onn\u00e9 par mur de force.Une cr\u00e9ature cibl\u00e9e par ce sort doit r\u00e9ussir un jet de sauvegarde de Dext\u00e9rit\u00e9 ou subir 10d6 + 40 d\u00e9g\u00e2ts de force. La cible est d\u00e9sint\u00e9gr\u00e9e si ces dommages la laissent \u00e0 0 point de vie.Une cr\u00e9ature d\u00e9sint\u00e9gr\u00e9e et tout ce qu'elle porte et transporte, \u00e0 l'exception des objets magiques, sont r\u00e9duits \u00e0 l'\u00e9tat de poussi\u00e8re. La cr\u00e9ature peut \u00eatre ramen\u00e9e \u00e0 la vie unique...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 7 ou sup\u00e9rieur, les d\u00e9g\u00e2ts sont augment\u00e9s de 3d6 pour chaque niveau d'emplacement au-del\u00e0 du niveau 6.", upcast_dice: "3d6", upcast_from: 6, save: "DEX"},
  "D\u00e9tection de la magie": {desc: "Pour la dur\u00e9e du sort, vous percevez la pr\u00e9sence de magie \u00e0 9 m\u00e8tres ou moins de vous. Si vous percevez de la magie de cette mani\u00e8re, vous pouvez utiliser votre action pour discerner une faible aura enveloppant une cr\u00e9ature ou un objet visible dans la zone qui pr\u00e9sente de la magie. Vous d\u00e9terminez aussi l'\u00e9cole de magie, le cas \u00e9ch\u00e9ant.Le sort peut outrepasser la plupart des obstacles mais il est bloqu\u00e9 par 30 cm de pierre, 2,50 cm de m\u00e9tal ordinaire, une mince feuille de plomb ou 90 cm de bois ou de terre."},
  "D\u00e9tection des pens\u00e9es": {desc: "Pour la dur\u00e9e du sort, vous pouvez lire les pens\u00e9es de certaines cr\u00e9atures. Lorsque vous incantez le sort et lors de votre action \u00e0 chaque tour jusqu'\u00e0 la fin du sort, vous pouvez concentrer votre esprit sur une cr\u00e9ature que vous pouvez voir \u00e0 9 m\u00e8tres ou moins de vous. Si la cr\u00e9ature choisie poss\u00e8de une Intelligence de 3 ou moins, ou si elle ne parle aucun langage, la cr\u00e9ature n'est pas affect\u00e9e.Vous lisez d'abord les pens\u00e9es superficielles de la cr\u00e9ature, ce qui occupe son esprit \u00e0 cet instant. Lors d'une action, vous pouvez diriger votre attention sur les pens\u00e9es d'une autre cr\u00e9ature ou ...", save: "WIS"},
  "D\u00e9tection du mal et du bien": {desc: "Pour la dur\u00e9e du sort, vous savez si une aberration, un c\u00e9leste, un \u00e9l\u00e9mentaire, une f\u00e9e, un fi\u00e9lon ou un mort-vivant est pr\u00e9sent dans un rayon de 9 m\u00e8tres autour de vous. Vous pouvez aussi d\u00e9terminer sa localisation. De la m\u00eame mani\u00e8re, vous savez si un objet ou un lieu \u00e0 9 m\u00e8tres ou moins de vous a \u00e9t\u00e9 consacr\u00e9 ou profan\u00e9.Le sort peut outrepasser la plupart des obstacles mais il est bloqu\u00e9 par 30 cm de pierre, 2,50 cm de m\u00e9tal ordinaire, une mince feuille de plomb ou 90 cm de bois ou de terre."},
  "D\u00e9tection du poison et des maladies": {desc: "Pour la dur\u00e9e du sort, vous pouvez percevoir la pr\u00e9sence et localiser les poisons, les cr\u00e9atures venimeuses, et les maladies dans un rayon de 9 m\u00e8tres autour de vous. Vous identifiez \u00e9galement le type de poison, de cr\u00e9ature venimeuse, ou de maladie.Le sort peut outrepasser la plupart des obstacles mais il est bloqu\u00e9 par 30 cm de pierre, 2,50 cm de m\u00e9tal ordinaire, une mince feuille de plomb ou 90 cm de bois ou de terre."},
  "Fabrication": {desc: "Vous convertissez des mat\u00e9riaux bruts en objets confectionn\u00e9s avec ces mati\u00e8res. Par exemple, vous pouvez fabriquer un pont en bois avec quelques arbres, une corde \u00e0 partir d'une parcelle de chanvre, et des v\u00eatements avec du lin ou de la laine.Choisissez des mat\u00e9riaux bruts que vous pouvez voir et \u00e0 port\u00e9e. Vous pouvez fabriquer un objet de taille G ou inf\u00e9rieure (pouvant tenir dans un cube de 3 m\u00e8tres d'ar\u00eate, ou dans huit cubes de 1,50 m\u00e8tre d'ar\u00eate), \u00e0 condition que vous utilisiez suffisamment de mati\u00e8re premi\u00e8re. Si vous utilisez ce sort en ciblant du m\u00e9tal, de la pierre, ou tout autre ..."},
  "Festin des h\u00e9ros": {desc: "Vous produisez un grand festin, incluant des breuvages et des mets magnifiques. Le festin prend 1 heure pour \u00eatre consomm\u00e9 et dispara\u00eet au bout de cette p\u00e9riode. C'est \u00e0 ce moment que les effets b\u00e9n\u00e9fiques s'appliquent. Jusqu'\u00e0 douze convives peuvent prendre part au festin.Une cr\u00e9ature qui partage le festin re\u00e7oit de nombreux b\u00e9n\u00e9fices. La cr\u00e9ature est gu\u00e9rie des maladies et des empoisonnements. Elle devient immunis\u00e9e aux poisons, ne peut \u00eatre effray\u00e9e et tous ses jets de sauvegarde de Sagesse ont un avantage. Son maximum de points de vie est aussi augment\u00e9 de 2d10 et elle gagne la m\u00eame qua...", save: "WIS"},
  "Feuille morte": {desc: "Choisissez jusqu'\u00e0 cinq cr\u00e9atures en chute libre dans la port\u00e9e du sort. Le taux de descente d'une cr\u00e9ature en chute libre est ramen\u00e9 \u00e0 18 m\u00e8tres par round jusqu'\u00e0 la fin du sort. Si la cr\u00e9ature atterrit avant la fin du sort, elle ne subit aucun d\u00e9g\u00e2t de chute et elle retombe sur ses pieds. Le sort prend alors fin pour cette cr\u00e9ature."},
  "Flamme sacr\u00e9e": {desc: "Un rayonnement semblable \u00e0 des flammes descend sur une cr\u00e9ature que vous pouvez voir dans la port\u00e9e du sort. La cible doit r\u00e9ussir un jet de sauvegarde de Dext\u00e9rit\u00e9 ou subir 1d8 d\u00e9g\u00e2ts radiants. La cible ne gagne aucun b\u00e9n\u00e9fice d'abri pour ce jet de sauvegarde.Les d\u00e9g\u00e2ts du sort augmentent de 1d8 lorsque vous atteignez le niveau 5 (2d8), le niveau 11 (3d8), et le niveau 17 (4d8).", save: "DEX"},
  "Flamme \u00e9ternelle": {desc: "Une flamme, d'une luminosit\u00e9 \u00e9quivalente \u00e0 celle d'une torche, fait \u00e9ruption depuis un objet que vous touchez. L'effet ressemble \u00e0 une flamme r\u00e9guli\u00e8re, mais il ne produit aucune chaleur et ne n\u00e9cessite pas d'oxyg\u00e8ne. Une flamme \u00e9ternelle peut \u00eatre recouverte ou dissimul\u00e9e, mais elle ne peut pas \u00eatre \u00e9touff\u00e9e ou \u00e9teinte."},
  "Fl\u00e8che acide de Melf": {desc: "Une fl\u00e8che verte scintillante jaillit en direction d'une cible \u00e0 port\u00e9e et l'asperge d'acide. Effectuez une attaque \u00e0 distance avec un sort contre la cible. Si l'attaque touche, la cible subit 4d4 d\u00e9g\u00e2ts d'acide imm\u00e9diatement et 2d4 d\u00e9g\u00e2ts d'acide \u00e0 la fin de son prochain tour. En cas d'\u00e9chec, la fl\u00e8che asperge la cible avec de l'acide, ne lui infligeant que la moiti\u00e9 des d\u00e9g\u00e2ts initiaux et aucun d\u00e9g\u00e2t \u00e0 la fin de son prochain tour.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 3 ou sup\u00e9rieur, les d\u00e9g\u00e2ts (initiaux et \u00e0 retardement) sont augment\u00e9s de 1d4 pour chaque niveau d'emplacement au-del\u00e0 du niveau 2.", upcast_dice: "1d4", upcast_from: 2},
  "Fl\u00e8ches enflamm\u00e9es": {desc: "Vous touchez un carquois contenant des fl\u00e8ches ou des carreaux. Quand une cible est touch\u00e9e par une attaque \u00e0 distance avec une arme qui utilise une des munitions provenant du carquois, la cible re\u00e7oit 1d6 d\u00e9g\u00e2ts de feu suppl\u00e9mentaires. La magie du sort se termine pour une munition donn\u00e9e lorsque celle-ci touche ou rate, et le sort cesse compl\u00e8tement lorsque douze munitions ont \u00e9t\u00e9 tir\u00e9es du carquois.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 4 ou sup\u00e9rieur, le nombre de munitions qui peut affecter ce sort augmente de deux pour chaque emplacement sup\u00e9rieur au niveau 3.", upcast_from: 4},
  "Fl\u00e9au": {desc: "Jusqu'\u00e0 trois cr\u00e9atures de votre choix, que vous pouvez voir et qui sont \u00e0 port\u00e9e, doivent effectuer un jet de sauvegarde de Charisme. Quand une cible qui a rat\u00e9 son jet de sauvegarde fait un jet d'attaque ou un autre jet de sauvegarde avant la fin du sort, elle doit lancer un d4 et soustraire le r\u00e9sultat \u00e0 son jet d'attaque ou de sauvegarde.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, vous pouvez cibler une cr\u00e9ature suppl\u00e9mentaire pour chaque niveau d'emplacement au-del\u00e0 du niveau 1.", upcast_from: 1, save: "CHA"},
  "Forme gazeuse": {desc: "Vous transformez une cr\u00e9ature consentante que vous touchez, ainsi que tout ce qu'elle porte et transporte, en un nuage brumeux pour la dur\u00e9e du sort. Le sort prend fin si la cr\u00e9ature atteint 0 point de vie. Une cr\u00e9ature immat\u00e9rielle n'est pas affect\u00e9e.Alors qu'elle est dans cet \u00e9tat, la cible ne peut se d\u00e9placer que par le vol, \u00e0 la vitesse de 3 m\u00e8tres. La cible peut p\u00e9n\u00e9trer et occuper l'espace d'une autre cr\u00e9ature. La cible poss\u00e8de une r\u00e9sistance aux d\u00e9g\u00e2ts non magiques, et elle a un avantage \u00e0 ses jets de sauvegarde de Force, Dext\u00e9rit\u00e9 et Constitution. La cible peut passer par de petits ...", save: "STR"},
  "Forme \u00e9th\u00e9r\u00e9e": {desc: "Vous faites un pas dans la zone p\u00e9riph\u00e9rique du plan \u00e9th\u00e9r\u00e9, dans un secteur qui chevauche votre plan actuel. Vous demeurez dans la Limite \u00e9th\u00e9r\u00e9e pour la dur\u00e9e du sort ou jusqu'\u00e0 ce que vous utilisiez une action pour dissiper le sort. Entre temps, vous pouvez vous d\u00e9placer dans toutes les directions. Si vous vous d\u00e9placez vers le haut ou vers le bas, chaque unit\u00e9 de distance compte double. Vous pouvez voir et entendre le plan d'o\u00f9 vous venez, mais tout vous parait gris et vous ne pouvez rien distinguer au-del\u00e0 de 18 m\u00e8tres.En \u00e9tant sur le plan \u00e9th\u00e9r\u00e9, vous ne pouvez affecter et \u00eatre affect...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 8 ou sup\u00e9rieur, vous pouvez cibler jusqu'\u00e0 trois cr\u00e9atures consentantes (vous y compris) pour chaque niveau d'emplacement au-del\u00e0 du niveau 7. Les cr\u00e9atures doivent \u00eatre dans un rayon de 3 m\u00e8tres autour de vous lorsque vous lancez le sort.", upcast_from: 7},
  "Gardien de la foi": {desc: "Un gardien spectral de taille G apparait et flotte au-dessus d'un espace de votre choix, inoccup\u00e9 et visible, dans la port\u00e9e et pour la dur\u00e9e du sort. Le gardien occupe cet espace et il est flou \u00e0 l'exception d'une \u00e9p\u00e9e \u00e9tincelante et d'un bouclier montrant le symbole de votre divinit\u00e9.Toute cr\u00e9ature vous \u00e9tant hostile qui se d\u00e9place pour la premi\u00e8re fois lors de son tour dans un espace \u00e0 3 m\u00e8tres ou moins du gardien doit effectuer un jet de sauvegarde de Dext\u00e9rit\u00e9, subissant 20 d\u00e9g\u00e2ts radiants en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite. Le gardien se volatilise apr\u00e8s avo...", save: "DEX"},
  "Glas fun\u00e8bre": {desc: "Vous pointez une cr\u00e9ature que vous pouvez voir \u00e0 port\u00e9e, et le son douloureux d'une cloche emplit l'air autour d'elle pendant un moment. La cible doit r\u00e9ussir un jet de sauvegarde de Sagesse ou subir 1d8 d\u00e9g\u00e2ts n\u00e9crotiques. Si la cible n'est pas \u00e0 son maximum de points de vie, elle subit 1d12 de d\u00e9g\u00e2ts n\u00e9crotiques.Les d\u00e9g\u00e2ts du sort augmentent de un d\u00e9 lorsque vous atteignez le niveau 5 (2d8 ou 2d12), le niveau 11 (3d8 ou 3d12) et le niveau 17 (4d8 ou 4d12).", save: "WIS"},
  "Globe d'invuln\u00e9rabilit\u00e9": {desc: "Une barri\u00e8re immobile et l\u00e9g\u00e8rement chatoyante prend la forme d'une sph\u00e8re de 3 m\u00e8tres de rayon autour de vous, et persiste pour la dur\u00e9e du sort.Tout sort de niveau 5 ou moins incant\u00e9 \u00e0 l'ext\u00e9rieur de la barri\u00e8re ne peut affecter les cr\u00e9atures et les objets qu'elle englobe, m\u00eame si le sort utilise un emplacement de sort sup\u00e9rieur. Un tel sort peut cibler les cr\u00e9atures et les objets \u00e0 l'int\u00e9rieur de la barri\u00e8re, mais ce sort n'a pas d'effet sur eux. De la m\u00eame mani\u00e8re, la zone \u00e0 l'int\u00e9rieur de la sph\u00e8re est exclue des zones affect\u00e9es par de tels sorts.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 7 ou sup\u00e9rieur, la barri\u00e8re bloque les sorts d'un niveau sup\u00e9rieur pour chaque niveau d'emplacement au-del\u00e0 du niveau 6.", upcast_from: 6},
  "Glyphe de protection": {desc: "Lorsque vous lancez ce sort, vous inscrivez un glyphe qui peut blesser d'autres cr\u00e9atures, sur une surface (comme une table ou une portion de plancher ou de mur) ou \u00e0 l'int\u00e9rieur d'un objet qui peut \u00eatre ferm\u00e9 (comme un livre, un parchemin ou un coffret) pour dissimuler le glyphe. Le glyphe peut couvrir un espace d'au plus 3 m\u00e8tres de diam\u00e8tre. Si la surface ou l'objet est d\u00e9plac\u00e9 de plus de 3 m\u00e8tres d'o\u00f9 vous avez lanc\u00e9 ce sort, le glyphe est cass\u00e9 et le sort se termine sans avoir \u00e9t\u00e9 activ\u00e9.Le glyphe est pratiquement invisible et un jet d'Intelligence (Investigation) contre le DD de sauve...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 4 ou sup\u00e9rieur, les d\u00e9g\u00e2ts des runes explosives augmentent de 1d8 pour chaque niveau d'emplacement au-del\u00e0 du niveau 3. Si vous cr\u00e9ez un sort glyphique, vous pouvez emmagasiner un sort dont le niveau est \u00e9quivalent ou moindre \u00e0 l'emplacement de sort utilis\u00e9 pour le glyphe de protection.", upcast_dice: "1d8", upcast_from: 3, save: "DEX"},
  "Graisse": {desc: "Une graisse visqueuse recouvre le sol sur un carr\u00e9 de 3 m\u00e8tres de c\u00f4t\u00e9 centr\u00e9 sur un point \u00e0 port\u00e9e, transformant cette zone en terrain difficile.Lorsque la graisse appara\u00eet, chaque cr\u00e9ature se tenant debout dans la zone doit r\u00e9ussir un jet de sauvegarde de Dext\u00e9rit\u00e9 sous peine de tomber \u00e0 terre. Une cr\u00e9ature qui entre dans la zone ou y termine son tour doit \u00e9galement r\u00e9ussir un jet de sauvegarde de Dext\u00e9rit\u00e9 si elle ne veut pas tomber \u00e0 terre.", save: "DEX"},
  "Grande foul\u00e9e": {desc: "Vous touchez une cr\u00e9ature. La vitesse de la cible augmente de 3 m\u00e8tres jusqu'\u00e0 la fin du sort.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, vous pouvez cibler une cr\u00e9ature suppl\u00e9mentaire pour chaque niveau d'emplacement au-del\u00e0 du niveau 1.", upcast_from: 1},
  "Gr\u00eale d'\u00e9pines": {desc: "La prochaine fois que vous touchez une cr\u00e9ature lors d'une attaque \u00e0 distance avec une arme avant que le sort ne prenne fin, ce sort cr\u00e9e une pluie d'\u00e9pines qui jaillissent de votre arme \u00e0 distance ou de la munition. En plus de l'effet normal de l'attaque, la cible de l'attaque et toutes les cr\u00e9atures \u00e0 1,50 m\u00e8tre ou moins d'elle doivent effectuer un jet de sauvegarde de Dext\u00e9rit\u00e9, subissant 1d10 d\u00e9g\u00e2ts perforants en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite.", upcast: "Aux niveaux sup\u00e9rieurs. Si vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, les d\u00e9g\u00e2ts augmentent de 1d10 pour chaque niveau d'emplacement au-del\u00e0 du niveau 1 (jusqu'\u00e0 un maximum de 6d10).", upcast_dice: "1d10", upcast_from: 1, save: "DEX"},
  "Gu\u00e9rison": {desc: "Choisissez une cr\u00e9ature que vous voyez dans la port\u00e9e du sort. Une d\u00e9charge d'\u00e9nergie positive engouffre la cr\u00e9ature lui permettant de r\u00e9cup\u00e9rer 70 points de vie. Ce sort met aussi un terme \u00e0 un aveuglement, une surdit\u00e9 et toutes autres maladies accablant la cible. Ce sort n'a pas d'effet sur les morts-vivants et les artificiels.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 7 ou sup\u00e9rieur, la quantit\u00e9 de points de vie r\u00e9cup\u00e9r\u00e9s est augment\u00e9e de 10 pour chaque niveau d'emplacement au-del\u00e0 du niveau 6.", upcast_from: 6},
  "Gu\u00e9rison de groupe": {desc: "Un flot d'\u00e9nergie curative \u00e9mane de votre personne vers les cr\u00e9atures bless\u00e9es qui vous entourent. Vous redonnez jusqu'\u00e0 700 points de vie, r\u00e9partis \u00e0 votre guise entre les cr\u00e9atures de votre choix qui sont visibles dans la port\u00e9e du sort. Les cr\u00e9atures soign\u00e9es par ce sort sont aussi gu\u00e9ries de toutes maladies et des effets qui les rendent sourds ou aveugles. Ce sort n'a pas d'effet sur les morts-vivants et les artificiels."},
  "H\u00e2te": {desc: "Choisissez une cr\u00e9ature consentante visible dans la port\u00e9e du sort. Jusqu'\u00e0 la fin de la dur\u00e9e du sort, la vitesse de la cible est doubl\u00e9e, elle b\u00e9n\u00e9ficie d'un bonus de +2 \u00e0 la CA, elle a un avantage \u00e0 ses jets de sauvegarde de Dext\u00e9rit\u00e9, et elle obtient une action suppl\u00e9mentaire \u00e0 chacun de ses tours. Cette action peut \u00eatre utilis\u00e9e pour Attaquer (une seule attaque avec une arme), Foncer, Se d\u00e9sengager, Se cacher ou Utiliser un objet.Lorsque le sort prend fin, la cible ne peut plus bouger ou agir jusqu'\u00e0 la fin de son prochain tour, car une vague de l\u00e9thargie la submerge.", save: "DEX"},
  "H\u00e9ro\u00efsme": {desc: "Une cr\u00e9ature consentante que vous touchez est submerg\u00e9e par le courage. Jusqu'\u00e0 la fin du sort, la cr\u00e9ature est immunis\u00e9e contre l'\u00e9tat effray\u00e9 et gagne un nombre de points de vie temporaires \u00e9gal au modificateur de votre caract\u00e9ristique d'incantation, et ce au d\u00e9but de chacun de ses tours. Lorsque le sort prend fin, la cible perd tous les points de vie temporaires qu'il lui restait et qui lui avaient \u00e9t\u00e9 conf\u00e9r\u00e9s par ce sort.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, vous pouvez cibler une cr\u00e9ature suppl\u00e9mentaire pour chaque niveau d'emplacement au-del\u00e0 du niveau 1.", upcast_from: 1},
  "Identification": {desc: "Vous choisissez un objet que vous devez toucher durant toute la dur\u00e9e du sort. Si l'objet est magique ou impr\u00e9gn\u00e9 de magie, vous apprenez ses propri\u00e9t\u00e9s et comment les utiliser, s'il requiert un lien pour \u00eatre utilis\u00e9 et le nombre de charges qu'il contient, le cas \u00e9ch\u00e9ant. Vous apprenez si des sorts affectent l'objet et quels sont ces sorts. Si l'objet a \u00e9t\u00e9 cr\u00e9\u00e9 par un ou plusieurs sorts, vous apprenez quels sorts ont permis de le cr\u00e9er.Si vous touchez une cr\u00e9ature durant toute la dur\u00e9e du sort, au lieu d'un objet, vous apprenez quels sorts l'affectent actuellement, le cas \u00e9ch\u00e9ant."},
  "Illusion mineure": {desc: "Le lanceur de sorts cr\u00e9e un son ou l'image d'un objet \u00e0 port\u00e9e pendant une minute. Cette illusion se termine \u00e9galement si elle est r\u00e9voqu\u00e9e au prix d'une action ou si ce sort est lanc\u00e9 une nouvelle fois.Si l'illusion est un son, le volume peut aller d'un simple chuchotement \u00e0 un cri. Il peut s'agir de votre voix, de la voix de quelqu'un d'autre, du rugissement d'un lion, d'un roulement de tambours, ou tout autre son que vous choisissez. Le son peut autant ne pas diminuer en intensit\u00e9 pendant la dur\u00e9e du sort qu'\u00eatre discret et produit \u00e0 diff\u00e9rents instants dans cet intervalle de temps.Si l'..."},
  "Image majeure": {desc: "Vous cr\u00e9ez l'image d'un objet, d'une cr\u00e9ature ou d'un quelconque ph\u00e9nom\u00e8ne visible qui ne d\u00e9borde pas d'un cube de 6 m\u00e8tres d'ar\u00eate. L'image apparait \u00e0 un endroit visible dans la port\u00e9e et pour la dur\u00e9e du sort. Elle parait bel et bien r\u00e9elle, incluant les sons, les odeurs et la temp\u00e9rature appropri\u00e9s \u00e0 la chose montr\u00e9e. Vous ne pouvez pas cr\u00e9er une chaleur ou un froid suffisamment intense pour infliger des d\u00e9g\u00e2ts, un son si fort qu'il inflige des d\u00e9g\u00e2ts de tonnerre ou qu'il assourdisse une cr\u00e9ature ou bien une odeur qui pourrait rendre une cr\u00e9ature malade (comme la puanteur d'un troglodyte...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 6 ou sup\u00e9rieur, le sort persiste jusqu'au moment de sa dissipation, sans requ\u00e9rir de concentration.", upcast_from: 6},
  "Image silencieuse": {desc: "Vous cr\u00e9ez l'image d'un objet, d'une cr\u00e9ature ou d'un autre ph\u00e9nom\u00e8ne visible dont les dimensions n'exc\u00e8dent pas un cube de 4,50 m\u00e8tres d'ar\u00eate. L'image appara\u00eet \u00e0 un endroit choisi \u00e0 l'int\u00e9rieur de la port\u00e9e du sort et perdure pendant toute la dur\u00e9e du sort. L'image est purement visuelle ; ce qui implique qu'elle n'est pas accompagn\u00e9e par un son, une odeur ou d'autres effets sensoriels.Vous pouvez utiliser votre action pour d\u00e9placer l'image \u00e0 n'importe quel endroit dans la port\u00e9e du sort. Comme l'image change de lieu, vous pouvez modifier son apparence afin que ses mouvements apparaissent ..."},
  "Injonction": {desc: "Vous donnez un ordre d'un mot \u00e0 une cr\u00e9ature dans la port\u00e9e du sort et que vous pouvez voir. La cible doit r\u00e9ussir un jet de sauvegarde de Sagesse ou suivre l'ordre lors de son prochain tour. Le sort n'a aucun effet si la cible est un mort-vivant, si elle ne comprend pas la langue, ou si votre ordre est directement nocif pour elle.Des injonctions typiques et leurs effets suivent. Vous pouvez \u00e9mettre un ordre autre que ceux d\u00e9crits ici. Si vous le faites, le MD d\u00e9termine comment la cible se comporte. Si la cible est emp\u00each\u00e9e de suivre votre ordre, le sort prend fin.Approche. La cible se d\u00e9pl...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, vous pouvez affecter une cr\u00e9ature suppl\u00e9mentaire pour chaque niveau d'emplacement au-del\u00e0 du niveau 1. Les cr\u00e9atures que vous ciblez doivent toutes \u00eatre dans un rayon de 9 m\u00e8tres.", upcast_from: 1, save: "WIS"},
  "Inversion de la gravit\u00e9": {desc: "Ce sort renverse la gravit\u00e9 dans un cylindre de 15 m\u00e8tres de rayon et 30 m\u00e8tres de haut centr\u00e9 sur un point \u00e0 port\u00e9e. Toutes les cr\u00e9atures et tous les objets dans la zone, qui ne sont pas maintenus au sol d'une mani\u00e8re ou d'une autre, tombent vers le haut et atteignent le point culminant de la zone au moment o\u00f9 vous lancez le sort. Une cr\u00e9ature peut effectuer un jet de sauvegarde de Dext\u00e9rit\u00e9 pour attraper un objet fix\u00e9 au sol qu'elle peut atteindre, et ainsi \u00e9viter de tomber.Si les cr\u00e9atures et objets rencontrent dans leur chute des objets solides (comme un plafond), ils le percutent comme...", save: "DEX"},
  "Invisibilit\u00e9 sup\u00e9rieure": {desc: "Vous ou une cr\u00e9ature que vous touchez devenez invisible jusqu'\u00e0 la fin de la dur\u00e9e du sort. Tout ce que porte ou transporte la cible est invisible tant que \u00e7a demeure sur sa personne."},
  "Lance de feu": {desc: "Vous cr\u00e9ez une lame ardente dans votre main libre. La lame est similaire en taille et en forme \u00e0 un cimeterre, et reste jusqu'\u00e0 ce que le sort prenne fin. Si vous l\u00e2chez la lame, elle dispara\u00eet, mais vous pouvez la r\u00e9invoquer par une action bonus.Vous pouvez utiliser votre action pour effectuer une attaque au corps \u00e0 corps avec un sort avec la lame ardente. Si le coup touche, la cible subit 3d6 d\u00e9g\u00e2ts de feu.La lame enflamm\u00e9e \u00e9met une lumi\u00e8re vive dans un rayon de 3 m\u00e8tres et une lumi\u00e8re faible sur 3 m\u00e8tres suppl\u00e9mentaires.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 4 ou sup\u00e9rieur, les d\u00e9g\u00e2ts augmentent de 1d6 tous les 2 niveaux d'emplacement au-dessus du niveau 2.", upcast_dice: "1d6", upcast_from: 4},
  "Lenteur": {desc: "Vous alt\u00e9rez le temps pour un maximum de six cr\u00e9atures de votre choix dans un cube de 12 m\u00e8tres d'ar\u00eate \u00e0 port\u00e9e. Chaque cible doit r\u00e9ussir un jet de sauvegarde de Sagesse ou \u00eatre affect\u00e9e par le sort pendant sa dur\u00e9e.Une cr\u00e9ature affect\u00e9e voit sa vitesse divis\u00e9e par deux, subit un malus de -2 \u00e0 sa CA et \u00e0 ses jets de sauvegarde de Dext\u00e9rit\u00e9 et ne peut utiliser de r\u00e9actions. \u00c0 son tour, elle ne peut utiliser qu'une action ou une action bonus, pas les deux. Peu importe ses capacit\u00e9s ou objets magiques, la cr\u00e9ature ne peut effectuer plus d'une attaque au corps \u00e0 corps ou \u00e0 distance pendant so...", save: "DEX"},
  "Libert\u00e9 de mouvement": {desc: "Vous touchez une cr\u00e9ature consentante. Pour la dur\u00e9e du sort, les mouvements de la cible ne sont pas limit\u00e9s par un terrain difficile. Les sorts et autres effets magiques ne peuvent ni r\u00e9duire la vitesse de la cible ni la rendre paralys\u00e9e ou entrav\u00e9e.La cible peut aussi d\u00e9penser 1,50 m\u00e8tre de son mouvement pour se d\u00e9gager d'une contrainte non magique, comme des menottes ou l'\u00e9treinte d'une cr\u00e9ature. Enfin, l'environnement aquatique n'impose aucune p\u00e9nalit\u00e9 sur les mouvements et les attaques de la cible."},
  "Lueurs f\u00e9eriques": {desc: "Tous les objets \u00e0 l'int\u00e9rieur d'un cube de 6 m\u00e8tres d'ar\u00eate dans la port\u00e9e du sort se distinguent par un halo bleu, vert ou violet (\u00e0 votre choix). Toutes les cr\u00e9atures pr\u00e9sentes dans la zone lors de l'incantation du sort sont \u00e9galement envelopp\u00e9es du halo si elles \u00e9chouent \u00e0 un jet de sauvegarde de Dext\u00e9rit\u00e9. Pour la dur\u00e9e du sort, les objets et les cr\u00e9atures affect\u00e9es \u00e9mettent une lumi\u00e8re faible dans un rayon de 3 m\u00e8tres.Les jets d'attaque contre des cr\u00e9atures affect\u00e9es ou des objets b\u00e9n\u00e9ficient d'un avantage si l'attaquant peut les voir. Les cr\u00e9atures affect\u00e9es ou les objets ne peuvent b...", save: "DEX"},
  "Lumi\u00e8re": {desc: "Vous touchez un objet qui ne d\u00e9passe pas 3 m\u00e8tres dans toutes les dimensions. Jusqu'\u00e0 la fin du sort, l'objet \u00e9met une lumi\u00e8re vive dans un rayon de 6 m\u00e8tres et une lumi\u00e8re faible sur 6 m\u00e8tres suppl\u00e9mentaires. La lumi\u00e8re est de la couleur que vous voulez. Couvrir compl\u00e8tement l'objet avec quelque chose d'opaque bloque la lumi\u00e8re. Le sort se termine si vous le lancez de nouveau ou si vous le dissipez par une action.Si vous ciblez un objet tenu ou port\u00e9 par une cr\u00e9ature hostile, cette cr\u00e9ature doit r\u00e9ussir un jet de sauvegarde de Dext\u00e9rit\u00e9 pour \u00e9viter le sort.", save: "DEX"},
  "Lumi\u00e8re du jour": {desc: "Une sph\u00e8re de lumi\u00e8re de 18 m\u00e8tres de rayon jaillit d'un point choisi dans la port\u00e9e du sort. La sph\u00e8re est compos\u00e9e de lumi\u00e8re vive et elle \u00e9met une lumi\u00e8re faible sur 18 m\u00e8tres suppl\u00e9mentaires.Si vous choisissez un point sur un objet que vous tenez ou sur un objet qui n'est pas port\u00e9 ou transport\u00e9, la lumi\u00e8re \u00e9mane de cet objet et se d\u00e9place avec lui. En recouvrant compl\u00e8tement l'objet affect\u00e9 avec un objet opaque, comme un bol ou un casque, la lumi\u00e8re est bloqu\u00e9e.Si une portion de la zone du sort chevauche une zone de t\u00e9n\u00e8bres cr\u00e9\u00e9e par un sort de niveau 3 ou moindre, le sort qui g\u00e9n\u00e8re ..."},
  "Lumi\u00e8res dansantes": {desc: "Ce sort permet de cr\u00e9er jusqu'\u00e0 quatre lumi\u00e8res, de la taille de torches, qui peuvent rev\u00eatir l'apparence de torches, de lanternes ou d'orbes brillantes qui flottent dans les airs. Il est possible de combiner les quatre lumi\u00e8res en une forme vaguement humano\u00efde brillante de taille M. Peu importe la forme choisie, chaque lumi\u00e8re produit une lumi\u00e8re faible qui \u00e9claire dans un rayon de 3 m\u00e8tres.Au prix d'une action bonus lors de votre tour, il est possible de d\u00e9placer les lumi\u00e8res jusqu'\u00e0 18 m\u00e8tres vers un nouvel emplacement \u00e0 port\u00e9e. Une lumi\u00e8re doit se situer \u00e0 6 m\u00e8tres ou moins d'une autre ..."},
  "L\u00e9vitation": {desc: "Une cr\u00e9ature ou un objet non tenu de votre choix, visible et \u00e0 port\u00e9e du sort, s'\u00e9l\u00e8ve jusqu'\u00e0 une hauteur de 6 m\u00e8tres et reste suspendu pour la dur\u00e9e du sort. Le sort peut faire l\u00e9viter une cible pesant jusqu'\u00e0 250 kg. Une cr\u00e9ature r\u00e9calcitrante qui r\u00e9ussit un jet de sauvegarde de Constitution n'est pas affect\u00e9e.La cible peut se d\u00e9placer seulement si elle se propulse ou se tire \u00e0 l'aide d'un objet ou d'une surface \u00e0 sa port\u00e9e (comme un mur ou un plafond). Elle peut ainsi se d\u00e9placer comme si elle grimpait. Vous pouvez changer l'altitude jusqu'\u00e0 6 m\u00e8tres dans une direction ou une autre \u00e0 vo...", save: "CON"},
  "Main du mage": {desc: "Une main spectrale appara\u00eet \u00e0 un point pr\u00e9cis choisi \u00e0 port\u00e9e. La main expire \u00e0 la fin de la dur\u00e9e du sort ou si elle est r\u00e9voqu\u00e9e au prix d'une action. La main dispara\u00eet si elle se retrouve \u00e0 plus de 9 m\u00e8tres du lanceur de sorts ou si ce sort est jet\u00e9 une nouvelle fois.Le lanceur de sorts peut utiliser son action pour contr\u00f4ler la main. La main peut manipuler un objet, ouvrir une porte ou un contenant non verrouill\u00e9, ranger ou r\u00e9cup\u00e9rer un objet d'un contenant ouvert, ou bien verser le contenu d'une fiole. La main peut \u00eatre d\u00e9plac\u00e9e jusqu'\u00e0 9 m\u00e8tres \u00e0 chaque fois que vous l'utilisez.La mai..."},
  "Mains br\u00fblantes": {desc: "En tendant vos mains, les pouces en contact et les doigts \u00e9cart\u00e9s, un mince rideau de flammes gicle du bout de tous vos doigts tendus. Toute cr\u00e9ature se trouvant dans le c\u00f4ne de 4,50 m\u00e8tres doit effectuer un jet de sauvegarde de Dext\u00e9rit\u00e9. La cr\u00e9ature subit 3d6 d\u00e9g\u00e2ts de feu en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite. Le feu embrase tous les objets inflammables qui se trouvent dans la zone d'effet et qui ne sont pas tenus ou port\u00e9s.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, les d\u00e9g\u00e2ts augmentent de 1d6 pour chaque niveau d'emplacement au-del\u00e0 du niveau 1.", upcast_dice: "1d6", upcast_from: 1, save: "DEX"},
  "Mal\u00e9diction": {desc: "Vous touchez une cr\u00e9ature, elle doit alors r\u00e9ussir un jet de sauvegarde de Sagesse sous peine d'\u00eatre afflig\u00e9e d'une mal\u00e9diction pour toute la dur\u00e9e du sort. Lorsque vous lancez ce sort, choisissez la nature de la mal\u00e9diction parmi les options qui suivent :\u2022 Choisissez une valeur de caract\u00e9ristique. Tant qu'elle est maudite, la cible a un d\u00e9savantage \u00e0 ses jets de caract\u00e9ristique et de sauvegarde effectu\u00e9s avec la caract\u00e9ristique en question.\u2022 Tant qu'elle est maudite, la cible a un d\u00e9savantage aux jets d'attaque qu'elle effectue contre vous.\u2022 Tant qu'elle est maudite, la cible doit effectue...", upcast: "Aux niveaux sup\u00e9rieurs. Si vous lancez ce sort en utilisant un emplacement de sort de niveau 4 ou sup\u00e9rieur, la dur\u00e9e de concentration maximale monte \u00e0 10 minutes. Si vous utilisez un emplacement de sort de niveau 5 ou sup\u00e9rieur, le sort dure 8 heures. Si vous utilisez un emplacement de sort de niveau 7 ou sup\u00e9rieur, le sort dure 24 heures. Si vous utilisez un emplacement de sort de niveau 9, le sort dure jusqu'\u00e0 ce qu'il soit dissip\u00e9. Utiliser un emplacement de sort de niveau 5 ou sup\u00e9rieur permet de s'affranchir de la concentration en ce qui concerne la dur\u00e9e du sort.", upcast_from: 4, save: "WIS"},
  "Marche sur l'eau": {desc: "Le sort attribue la capacit\u00e9 de se d\u00e9placer sur toute surface liquide (eau, acide, boue, neige, sables mouvants, lave, etc.) comme si c'\u00e9tait un sol dur. Les cr\u00e9atures qui traversent de la lave en fusion subissent tout de m\u00eame les d\u00e9g\u00e2ts dus \u00e0 la chaleur. Jusqu'\u00e0 dix cr\u00e9atures consentantes et que vous pouvez voir dans la port\u00e9e du sort obtiennent cette capacit\u00e9 pour la dur\u00e9e du sort.Si vous ciblez une cr\u00e9ature submerg\u00e9e dans un liquide, le sort d\u00e9place la cible vers la surface du liquide \u00e0 une vitesse de 18 m\u00e8tres par round."},
  "Marque du chasseur": {desc: "Vous choisissez une cr\u00e9ature que vous pouvez voir et \u00e0 port\u00e9e, et la marquez magiquement comme \u00e9tant votre cible. Jusqu'\u00e0 ce que le sort prenne fin, vous infligez 1d6 d\u00e9g\u00e2ts suppl\u00e9mentaires \u00e0 la cible lorsque vous la touchez lors d'une attaque avec une arme, et vous avez un avantage \u00e0 tous vos jets de Sagesse (Perception) ou Sagesse (Survie) effectu\u00e9s pour la trouver. Si la cible tombe \u00e0 0 point de vie avant que le sort ne prenne fin, vous pouvez utiliser votre action bonus lors de l'un de vos tours suivants pour marquer une nouvelle cr\u00e9ature.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 3 ou 4, vous pouvez maintenir votre concentration sur ce sort pendant 8 heures maximum. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 5 ou sup\u00e9rieur, vous pouvez maintenir votre concentration sur ce sort pendant 24 heures maximum.", upcast_from: 5},
  "Message": {desc: "Vous pointez votre doigt en direction d'une cr\u00e9ature \u00e0 port\u00e9e et murmurez un message. La cible (et seulement la cible) entend le message et peut r\u00e9pondre en un murmure que vous seul pouvez entendre. Vous pouvez lancer ce sort \u00e0 travers des objets solides si vous connaissez bien la cible et que vous savez qu'elle est derri\u00e8re l'obstacle. Ce sort est arr\u00eat\u00e9 par un silence magique, 30 cm de pierre, 2,50 cm de m\u00e9tal, une fine feuille de plomb ou 90 cm de bois. Ce sort ne doit pas forc\u00e9ment suivre une ligne droite et peut contourner les angles ou passer par de petites ouvertures."},
  "Missile magique": {desc: "Vous cr\u00e9ez trois fl\u00e9chettes de force magique d'un bleu lumineux. Chaque fl\u00e9chette atteint une cr\u00e9ature de votre choix que vous pouvez voir et dans la limite de port\u00e9e du sort. Chaque projectile inflige 1d4 + 1 d\u00e9g\u00e2ts de force \u00e0 sa cible. Les fl\u00e9chettes frappent simultan\u00e9ment, et peuvent frapper une ou plusieurs cr\u00e9atures.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, il cr\u00e9e une fl\u00e9chette additionnelle pour chaque niveau d'emplacement au-del\u00e0 du niveau 1.", upcast_from: 1},
  "Modification d'apparence": {desc: "Vous endossez une nouvelle forme. Lorsque vous lancez ce sort, choisissez l'une des options suivantes, dont les effets s'appliqueront jusqu'\u00e0 ce que le sort prenne fin. Tant que le sort est actif, vous pouvez mettre un terme \u00e0 une option, en d\u00e9pensant une action, pour gagner les b\u00e9n\u00e9fices d'une option diff\u00e9rente.Adaptation aquatique. Vous adaptez votre corps \u00e0 un environnement aquatique, en vous faisant pousser des branchies et des expansions palmaires entre les doigts. Vous pouvez respirer sous l'eau et obtenez une vitesse de nage \u00e9gale \u00e0 votre vitesse de marche.Changement d'apparence. Vou..."},
  "Mot de gu\u00e9rison": {desc: "Une cr\u00e9ature visible de votre choix r\u00e9cup\u00e8re des points de vie \u00e0 hauteur de 1d4 + le modificateur de votre caract\u00e9ristique d'incantation. Ce sort n'a pas d'effet sur les morts-vivants et les artificiels.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, les points de vie r\u00e9cup\u00e9r\u00e9s augmentent de 1d4 pour chaque niveau d'emplacement au-del\u00e0 du niveau 1.", upcast_dice: "1d4", upcast_from: 1},
  "Mot de pouvoir mortel": {desc: "Vous prononcez un mot de pouvoir qui peut contraindre une cr\u00e9ature que vous pouvez voir et \u00e0 port\u00e9e de sort \u00e0 mourir instantan\u00e9ment. Si la cr\u00e9ature poss\u00e8de 100 points de vie ou moins, elle meurt. Dans le cas contraire, le sort n'a aucun effet."},
  "Mot de radiance": {desc: "Vous prononcez un mot divin et un \u00e9clat br\u00fblant jaillit de vous. Toutes les cr\u00e9atures de votre choix \u00e0 port\u00e9e et que vous pouvez voir doivent r\u00e9ussir un jet de sauvegarde de Constitution ou bien prendre 1d6 d\u00e9g\u00e2ts radiants.Les d\u00e9g\u00e2ts du sort augmentent de 1d6 lorsque vous atteignez le niveau 5 (2d6), le niveau 11 (3d6) et le niveau 17 (4d6).", save: "CON"},
  "Mot de ralliement": {desc: "\u00c0 mesure que vous \u00e9voquez des paroles de r\u00e9tablissement, jusqu'\u00e0 six cr\u00e9atures visibles de votre choix r\u00e9cup\u00e8rent un nombre de points de vie \u00e9gal \u00e0 1d4 + le modificateur de votre caract\u00e9ristique d'incantation. Ce sort n'a pas d'effet sur les morts-vivants et les artificiels.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 4 ou sup\u00e9rieur, les points de vie r\u00e9cup\u00e9r\u00e9s augmentent de 1d4 pour chaque niveau d'emplacement au-del\u00e0 du niveau 3.", upcast_dice: "1d4", upcast_from: 3},
  "Mur de feu": {desc: "Vous cr\u00e9ez un mur de flammes sur une surface solide dans la port\u00e9e du sort. Vous pouvez fa\u00e7onner le mur jusqu'\u00e0 18 m\u00e8tres de longueur, 6 m\u00e8tres de hauteur et 30 cm d'\u00e9paisseur. Vous pouvez \u00e9galement en faire un mur circulaire de 6 m\u00e8tres de diam\u00e8tre, 6 m\u00e8tres de hauteur et 30 cm d'\u00e9paisseur. Le mur est opaque et persiste pour la dur\u00e9e du sort.Lorsque le mur appara\u00eet, chaque cr\u00e9ature dans la zone doit effectuer un jet de sauvegarde de Dext\u00e9rit\u00e9, subissant 5d8 d\u00e9g\u00e2ts de feu en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite.Un c\u00f4t\u00e9 du mur, que vous d\u00e9terminez lors de l'incantation ...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 5 ou sup\u00e9rieur, les d\u00e9g\u00e2ts du sort augmentent de 1d8 pour chaque niveau d'emplacement au-del\u00e0 du niveau 4.", upcast_dice: "1d8", upcast_from: 4, save: "DEX"},
  "Mur de glace": {desc: "Vous cr\u00e9ez un mur de glace sur une surface solide \u00e0 port\u00e9e. Vous pouvez lui donner la forme d'un d\u00f4me h\u00e9misph\u00e9rique ou d'une sph\u00e8re de 3 m\u00e8tres de rayon maximum, ou bien lui donner la forme d'une surface plane compos\u00e9e de 10 panneaux de 3 m\u00e8tres de c\u00f4t\u00e9 chacun, chaque panneau devant \u00eatre contigu \u00e0 un autre panneau. Quelle que soit sa forme, le mur est \u00e9pais de 30 cm et reste en place pendant toute la dur\u00e9e du sort.Si le mur traverse l'espace occup\u00e9 par une cr\u00e9ature lorsqu'il appara\u00eet, la cr\u00e9ature est repouss\u00e9e d'un c\u00f4t\u00e9 du mur et doit effectuer un jet de sauvegarde de Dext\u00e9rit\u00e9. La cr\u00e9ature...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 7 ou sup\u00e9rieur, les d\u00e9g\u00e2ts qu'inflige le mur lorsqu'il appara\u00eet augmentent de 2d6, et les d\u00e9g\u00e2ts inflig\u00e9s aux cr\u00e9atures qui traversent le voile d'air glacial augmentent de 1d6, pour chaque niveau d'emplacement au-del\u00e0 du niveau 6.", upcast_dice: "2d6", upcast_from: 6, save: "DEX"},
  "Mur de pierre": {desc: "Un mur non magique de pierre solide \u00e9merge \u00e0 un point que vous choisissez dans la port\u00e9e. Le mur fait 15 cm d'\u00e9paisseur et est compos\u00e9 de dix panneaux de 3 m\u00e8tres sur 3 m\u00e8tres. Chaque panneau doit \u00eatre contigu avec au moins un autre panneau. Vous pouvez aussi cr\u00e9er des panneaux de 3 m\u00e8tres par 6 m\u00e8tres qui ne font que de 7,50 cm d'\u00e9paisseur.Si le mur traverse l'espace d'une cr\u00e9ature quand il appara\u00eet, la cr\u00e9ature est pouss\u00e9e d'un c\u00f4t\u00e9 du mur (\u00e0 votre choix). Si une cr\u00e9ature devrait \u00eatre entour\u00e9e de tous c\u00f4t\u00e9s par le mur (ou par le mur et une autre surface solide), cette cr\u00e9ature peut alors ...", save: "DEX"},
  "Mur de sable": {desc: "Vous cr\u00e9ez un mur de sable tourbillonnant sur le sol \u00e0 un point que vous pouvez voir \u00e0 port\u00e9e. Vous pouvez cr\u00e9er un mur mesurant jusqu'\u00e0 9 m\u00e8tres de long, 3 m\u00e8tres de haut et 3 m\u00e8tres d'\u00e9paisseur, qui dispara\u00eetra \u00e0 la fin du sort. Il bloque la ligne de vue, mais pas le d\u00e9placement. Une cr\u00e9ature est aveugl\u00e9e tant qu'elle se trouve dans l'espace occup\u00e9 par le mur et doit d\u00e9penser 3 m\u00e8tres de mouvement pour 1 m\u00e8tre parcouru dans celui-ci."},
  "Mur de vent": {desc: "Un mur de puissants vents s'\u00e9l\u00e8ve du sol \u00e0 un endroit de votre choix. Vous pouvez cr\u00e9er un mur pouvant faire, au mieux, 15 m\u00e8tres de long, 4,50 m\u00e8tres de haut et 30 cm d'\u00e9paisseur. Vous pouvez donner au mur la forme que vous souhaitez, \u00e0 condition qu'il soit continuellement en contact avec le sol. Le mur reste en place pour toute la dur\u00e9e du sort.Lorsque le mur appara\u00eet, chaque cr\u00e9ature se trouvant dans la zone doit effectuer un jet de sauvegarde de Force. Une cr\u00e9ature subit 3d8 d\u00e9g\u00e2ts contondants en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite.Le vent violent garde les brumes...", save: "STR"},
  "M\u00e9tal br\u00fblant": {desc: "Choisissez un objet m\u00e9tallique manufactur\u00e9, comme une arme en m\u00e9tal ou une armure m\u00e9tallique interm\u00e9diaire ou lourde, \u00e0 port\u00e9e et que vous pouvez voir. Vous rendez l'objet rougeoyant d'une intense chaleur. Toutes les cr\u00e9atures \u00e9tant en contact physique avec l'objet subissent 2d8 d\u00e9g\u00e2ts de feu au moment o\u00f9 vous lancez le sort. Jusqu'\u00e0 la fin du sort, vous pouvez utiliser votre action bonus \u00e0 chacun des tours suivants pour infliger de nouveau ces d\u00e9g\u00e2ts de feu.Si une cr\u00e9ature tient ou porte l'objet et en subit les d\u00e9g\u00e2ts de feu, la cr\u00e9ature doit r\u00e9ussir un jet de sauvegarde de Constitution so...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 3 ou sup\u00e9rieur, les d\u00e9g\u00e2ts sont augment\u00e9s de 1d8 pour chaque niveau d'emplacement au-del\u00e0 du niveau 2.", upcast_dice: "1d8", upcast_from: 2, save: "CON"},
  "Nappe de brouillard": {desc: "Vous cr\u00e9ez une sph\u00e8re de brouillard de 6 m\u00e8tres de rayon centr\u00e9e sur un point dans la port\u00e9e du sort. La sph\u00e8re s'\u00e9tend au-del\u00e0 des coins et la visibilit\u00e9 dans la zone est nulle. Elle persiste pour la dur\u00e9e du sort ou jusqu'\u00e0 ce qu'un vent de force mod\u00e9r\u00e9e ou plus (au moins 15 km/h) la dissipe.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, le rayon de la sph\u00e8re augmente de 6 m\u00e8tres pour chaque niveau d'emplacement au-del\u00e0 du niveau 1.", upcast_from: 1},
  "Nu\u00e9e de m\u00e9t\u00e9ores": {desc: "Des orbes de feux ardents s'abattent sur le sol \u00e0 quatre diff\u00e9rents points visibles dans la port\u00e9e du sort. Toute cr\u00e9ature \u00e0 l'int\u00e9rieur d'une sph\u00e8re de 12 m\u00e8tres de rayon centr\u00e9e sur chaque point doit effectuer un jet de sauvegarde de Dext\u00e9rit\u00e9, subissant 20d6 d\u00e9g\u00e2ts de feu et 20d6 d\u00e9g\u00e2ts contondants en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite. L'effet de la sph\u00e8re contourne les coins. Une cr\u00e9ature prise dans plus d'une sph\u00e8re n'est affect\u00e9e qu'une seule fois.Le sort endommage les objets dans la zone et enflamme les objets inflammables qui ne sont pas port\u00e9s ou transport\u00e9s.", save: "DEX"},
  "Passe-muraille": {desc: "Un passage appara\u00eet \u00e0 un endroit de votre choix que vous pouvez voir sur une surface en bois, en pl\u00e2tre ou en pierre (tel qu'un mur, un plancher ou un plafond) \u00e0 port\u00e9e, et dispara\u00eet \u00e0 la fin du sort. Vous choisissez la taille de l'ouverture (jusqu'\u00e0 1,50 m\u00e8tre de large, 2,50 m\u00e8tres de haut et 6 m\u00e8tres de profondeur. Le passage n'engendre pas d'instabilit\u00e9 dans la structure environnante.Quand l'ouverture dispara\u00eet, toutes cr\u00e9atures ou tous objets encore pr\u00e9sents dans le passage cr\u00e9\u00e9 se retrouvent \u00e9ject\u00e9s sans dommage vers un endroit non occup\u00e9 pr\u00e8s de la surface sur laquelle a \u00e9t\u00e9 lanc\u00e9 le ..."},
  "Portail": {desc: "Vous invoquez un portail reliant un espace inoccup\u00e9 que vous voyez dans la port\u00e9e du sort \u00e0 un endroit pr\u00e9cis sur un plan d'existence diff\u00e9rent. Le portail se pr\u00e9sente comme une ouverture circulaire, dont vous contr\u00f4lez le diam\u00e8tre, entre 1,50 et 6 m\u00e8tres. Vous pouvez orienter le portail dans n'importe quelle direction. Le portail persiste selon la dur\u00e9e du sort.Le portail poss\u00e8de un avant et un arri\u00e8re sur chaque plan o\u00f9 il apparait. Le passage dans le portail n'est possible qu'en p\u00e9n\u00e9trant par l'avant. Tout ce qui traverse est instantan\u00e9ment transport\u00e9 sur l'autre plan pour appara\u00eetre dan..."},
  "Porte dimensionnelle": {desc: "Vous vous t\u00e9l\u00e9portez de votre position actuelle vers un autre endroit dans la port\u00e9e du sort. Vous arrivez exactement \u00e0 l'endroit d\u00e9sir\u00e9. Ce peut \u00eatre un lieu que vous voyez, que vous visualisez ou que vous pouvez d\u00e9crire en \u00e9non\u00e7ant une distance et une direction, comme \u00ab 60 m\u00e8tres droit devant \u00bb ou \u00ab vers le haut, \u00e0 45 degr\u00e9s sur 90 m\u00e8tres \u00bb.Vous pouvez transporter des objets tant que leurs poids ne d\u00e9passent pas votre capacit\u00e9 de chargement. Vous pouvez aussi emmener une cr\u00e9ature consentante de votre taille ou plus petite, qui porte de l'\u00e9quipement jusqu'\u00e0 sa capacit\u00e9 de chargement. La cr..."},
  "Prestidigitation": {desc: "Ce sort est un tour de magie mineur que les lanceurs de sorts novices emploient comme exercice. Ce sort permet de provoquer l'un des effets magiques suivants :\u2022 Le sort cr\u00e9e instantan\u00e9ment un effet sensoriel inoffensif, comme une pluie d'\u00e9tincelles, une bouff\u00e9e d'air, de timides notes de musique, ou une \u00e9trange odeur.\u2022 Le sort allume ou \u00e9teint instantan\u00e9ment une bougie, torche ou un petit feu de camp.\u2022 Le sort nettoie ou souille instantan\u00e9ment un objet pas plus volumineux qu'un cube de 30 cm d'ar\u00eate.\u2022 Le sort r\u00e9chauffe, refroidit ou assaisonne du mat\u00e9riel non vivant pouvant \u00eatre contenu dan..."},
  "Pri\u00e8re de gu\u00e9rison": {desc: "Jusqu'\u00e0 six cr\u00e9atures de votre choix visibles dans la port\u00e9e du sort r\u00e9cup\u00e8rent chacune des points de vie \u00e9quivalant \u00e0 2d8 + le modificateur de votre caract\u00e9ristique d'incantation. Ce sort n'a pas d'effet sur les morts-vivants et les artificiels.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 3 ou sup\u00e9rieur, les points de vie r\u00e9cup\u00e9r\u00e9s augmentent de 1d8 pour chaque niveau d'emplacement au-del\u00e0 du niveau 2.", upcast_dice: "1d8", upcast_from: 2},
  "Protection contre le mal et le bien": {desc: "Jusqu'\u00e0 ce que le sort prenne fin, une cr\u00e9ature consentante que vous touchez est prot\u00e9g\u00e9e contre certains types de cr\u00e9atures : les aberrations, les c\u00e9lestes, les \u00e9l\u00e9mentaires, les f\u00e9es, les fi\u00e9lons et les morts-vivants.La protection conf\u00e8re un certain nombre de b\u00e9n\u00e9fices. Les cr\u00e9atures de ces types ont un d\u00e9savantage \u00e0 leurs jets d'attaque effectu\u00e9s contre la cible. De plus, elles ne peuvent ni effrayer, ni charmer, ni poss\u00e9der la cible. Si la cible est d\u00e9j\u00e0 charm\u00e9e, effray\u00e9e, ou poss\u00e9d\u00e9e par une telle cr\u00e9ature, la cible a un avantage \u00e0 tout nouveau jet de sauvegarde qu'elle effectuerait co..."},
  "Protection contre le poison": {desc: "Vous touchez une cr\u00e9ature. Si elle est empoisonn\u00e9e, vous neutralisez le poison. Si plus d'un poison affecte la cible, vous neutralisez un des poisons dont vous \u00eates conscient de la pr\u00e9sence, sinon vous neutralisez l'un des poisons au hasard.Pour toute la dur\u00e9e du sort, la cible a un avantage \u00e0 ses jets de sauvegarde effectu\u00e9s pour \u00e9viter d'\u00eatre empoisonn\u00e9e, et a une r\u00e9sistance aux d\u00e9g\u00e2ts de poison."},
  "Pr\u00e9monition": {desc: "Vous touchez une cr\u00e9ature consentante pour lui octroyer une facult\u00e9 limit\u00e9e de voir son futur imm\u00e9diat. Pour la dur\u00e9e du sort, la cible ne peut \u00eatre surprise et elle b\u00e9n\u00e9ficie d'un avantage aux jets d'attaque, de sauvegarde et de caract\u00e9ristique. De plus, les jets d'attaque des autres cr\u00e9atures contre la cible ont un d\u00e9savantage pour la dur\u00e9e du sort.Le sort prend imm\u00e9diatement fin si vous l'incantez \u00e0 nouveau avant la fin de la dur\u00e9e."},
  "Rappel \u00e0 la vie": {desc: "Vous ramenez \u00e0 la vie une cr\u00e9ature morte depuis moins de 10 jours que vous touchez. Si l'\u00e2me de la cr\u00e9ature est \u00e0 la fois consentante et libre de rejoindre le corps, la cr\u00e9ature revient \u00e0 la vie avec 1 point de vie.Ce sort neutralise les poisons et gu\u00e9rit les maladies normales affligeant la cr\u00e9ature au moment de sa mort. Cependant, il n'enraye pas les maladies magiques, les mal\u00e9dictions et autres affections du genre. Si de tels effets ne sont pas enray\u00e9s avant l'incantation du sort, ils affligent toujours la cible \u00e0 son retour \u00e0 la vie. Ce sort ne peut rappeler un mort-vivant \u00e0 la vie.Ce so..."},
  "Rayon affaiblissant": {desc: "Un rayon noir d'\u00e9nergie n\u00e9gative s'\u00e9chappe de votre doigt en direction d'une cr\u00e9ature \u00e0 port\u00e9e. Effectuez une attaque \u00e0 distance avec un sort contre la cible. Si le coup touche, la cible n'inflige plus que la moiti\u00e9 de ses d\u00e9g\u00e2ts lorsqu'elle attaque avec une arme utilisant la Force, et ce jusqu'\u00e0 la fin du sort.\u00c0 la fin de chacun de ses tours, la cible effectue un jet de sauvegarde de Constitution contre le sort. En cas de r\u00e9ussite, le sort prend fin.", save: "CON"},
  "Rayon de givre": {desc: "Un faisceau glacial de lumi\u00e8re bleu\u00e2tre se dirige vers une cr\u00e9ature dans la port\u00e9e du sort. Effectuez une attaque \u00e0 distance avec un sort contre la cible. S'il touche, la cible subit 1d8 d\u00e9g\u00e2ts de froid et sa vitesse est r\u00e9duite de 3 m\u00e8tres jusqu'\u00e0 d\u00e9but de votre prochain tour.Les d\u00e9g\u00e2ts du sort augmentent de 1d8 lorsque vous atteignez le niveau 5 (2d8), le niveau 11 (3d8) et le niveau 17 (4d8)."},
  "Rayon de lune": {desc: "Un rayon argent\u00e9 de lumi\u00e8re p\u00e2le brille dans un cylindre de 12 m\u00e8tres de haut et 1,50 m\u00e8tre de rayon, centr\u00e9 sur un point \u00e0 port\u00e9e. Jusqu'\u00e0 ce que le sort prenne fin, une lumi\u00e8re faible remplit le cylindre.Lorsqu'une cr\u00e9ature p\u00e9n\u00e8tre la zone d'effet du sort pour la premi\u00e8re fois dans un tour, ou qu'elle y d\u00e9bute son tour, elle est envelopp\u00e9e de flammes fantomatiques qui lui provoquent d'intenses douleurs, l'obligeant \u00e0 effectuer un jet de sauvegarde de Constitution. Elle subit 2d10 d\u00e9g\u00e2ts radiants en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite.Un m\u00e9tamorphe effectue son jet d...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 3 ou sup\u00e9rieur, les d\u00e9g\u00e2ts augmentent de 1d10 pour chaque niveau d'emplacement au-del\u00e0 du niveau 2.", upcast_dice: "1d10", upcast_from: 2, save: "CON"},
  "Respiration aquatique": {desc: "Ce sort procure \u00e0 un maximum de dix cr\u00e9atures consentantes, \u00e0 port\u00e9e et que vous pouvez voir, la capacit\u00e9 de respirer sous l'eau jusqu'\u00e0 la fin de sa dur\u00e9e. Les cr\u00e9atures affect\u00e9es conservent \u00e9galement leur mode de respiration normal."},
  "Restauration partielle": {desc: "Vous touchez une cr\u00e9ature et vous pouvez mettre fin \u00e0 une maladie ou \u00e0 un \u00e9tat l'affligeant. L'\u00e9tat peut \u00eatre aveugl\u00e9, assourdi, paralys\u00e9 ou empoisonn\u00e9."},
  "R\u00e9g\u00e9n\u00e9ration": {desc: "Vous touchez une cr\u00e9ature afin de stimuler sa capacit\u00e9 \u00e0 gu\u00e9rir naturellement. La cible r\u00e9cup\u00e8re 4d8 + 15 points de vie. Pour la dur\u00e9e du sort, la cible recouvre 1 point de vie au d\u00e9but de chacun de ses tours (10 points de vie par minute).Les membres de la cible qui sont sectionn\u00e9s (doigts, jambes, queues, etc.) repoussent apr\u00e8s 2 minutes, le cas \u00e9ch\u00e9ant. Si vous tenez le membre en question et que vous l'approchez du moignon, le sort permet de rattacher instantan\u00e9ment le membre au moignon."},
  "R\u00e9paration": {desc: "Ce sort r\u00e9pare une simple fissure, d\u00e9chirure ou f\u00ealure sur un objet que vous touchez, comme un maillon de cha\u00eene cass\u00e9, une cl\u00e9 bris\u00e9e en deux morceaux, un accroc sur un manteau ou une fuite sur une outre. Tant que la fissure ou l'accroc n'exc\u00e8de pas 30 cm dans toutes les dimensions, vous le r\u00e9parez, ne laissant aucune trace de la d\u00e9t\u00e9rioration pass\u00e9e. Ce sort peut r\u00e9parer physiquement un objet magique ou un artificiel, mais ne peut pas rendre sa magie \u00e0 un objet."},
  "R\u00e9sistance": {desc: "Vous touchez une cr\u00e9ature consentante. Une fois avant la fin du sort, la cible peut lancer un d4 et ajouter le r\u00e9sultat du d\u00e9 \u00e0 un jet de sauvegarde de son choix. Elle peut lancer le d\u00e9 avant ou apr\u00e8s avoir effectu\u00e9 son jet de sauvegarde. Le sort prend alors fin."},
  "R\u00e9surrection": {desc: "Vous touchez une cr\u00e9ature qui est morte depuis moins d'un si\u00e8cle, qui n'est pas d\u00e9c\u00e9d\u00e9e de vieillesse et qui n'est pas un mort-vivant. Si son \u00e2me est libre et consentante, la cible revient \u00e0 la vie avec tous ses points de vie.Ce sort neutralise les poisons et gu\u00e9rit les maladies normales affligeant la cr\u00e9ature au moment de sa mort. Cependant, il n'enraye pas les maladies magiques, les mal\u00e9dictions et autres affections du genre. Si de tels effets ne sont pas enray\u00e9s avant l'incantation du sort, ils affligent toujours la cible \u00e0 son retour \u00e0 la vie.Ce sort referme les blessures mortelles et r..."},
  "Sanctuaire": {desc: "Vous prot\u00e9gez une cr\u00e9ature dans la port\u00e9e du sort contre les attaques. Jusqu'\u00e0 ce que le sort se termine, toute cr\u00e9ature qui cible la cr\u00e9ature prot\u00e9g\u00e9e avec une attaque ou un sort offensif doit d'abord effectuer un jet de sauvegarde de Sagesse. En cas d'\u00e9chec, la cr\u00e9ature doit choisir une nouvelle cible ou perdre son attaque ou son sort. Ce sort ne prot\u00e8ge pas la cr\u00e9ature prot\u00e9g\u00e9e contre les sorts \u00e0 zone d'effet, tel que l'explosion d'une boule de feu.Si la cr\u00e9ature prot\u00e9g\u00e9e fait une attaque, lance un sort qui affecte une cr\u00e9ature ennemie ou inflige des d\u00e9g\u00e2ts \u00e0 une autre cr\u00e9ature, ce sort ...", save: "WIS"},
  "Saut": {desc: "Vous touchez une cr\u00e9ature. La distance de saut de la cr\u00e9ature est tripl\u00e9e pour la dur\u00e9e du sort."},
  "Sauvagerie primitive": {desc: "Vous canalisez la magie primale pour qu'elle aiguise vos dents ou vos ongles, le rendant pr\u00eats \u00e0 livrer une attaque corrosive. Effectuez une attaque au corps \u00e0 corps avec un sort contre une cr\u00e9ature situ\u00e9e \u00e0 1,50 m\u00e8tre ou moins de vous. En cas de r\u00e9ussite, la cible prend 1d10 d\u00e9g\u00e2ts d'acide. Apr\u00e8s que vous ayez effectu\u00e9 votre attaque, vos dents ou vos ongles reprennent leur \u00e9tat normal.Les d\u00e9g\u00e2ts du sort augmentent de 1d10 lorsque vous atteignez le niveau 5 (2d10), le niveau 11 (3d10) et le niveau 17 (4d10)."},
  "Scrutation": {desc: "Vous pouvez voir et entendre une cr\u00e9ature sp\u00e9cifique que vous choisissez et qui se trouve dans le m\u00eame plan d'existence que vous. La cible doit effectuer un jet de sauvegarde de Sagesse, avec un modificateur d\u00e9pendant de votre niveau de connaissance et du lien physique qui vous relie \u00e0 elle. Si la cible sait que vous lancez ce sort, elle peut choisir d'\u00e9chouer volontairement son jet de sauvegarde si elle souhaite \u00eatre observ\u00e9e.ConnaissanceModificateurau jet desauvegardeSeconde main (vous avez entendu parler de la cible)+5Premi\u00e8re main (vous avez rencontr\u00e9 la cible)+0Familier (vous connaisse...", save: "WIS"},
  "Serviteur invisible": {desc: "Ce sort cr\u00e9e une force invisible, sans volont\u00e9 propre, informe mais de taille M, qui ex\u00e9cute les ordres simples que vous lui transmettez, jusqu'\u00e0 la fin du sort. Le serviteur prend vie dans un espace inoccup\u00e9 sur le sol et \u00e0 port\u00e9e. Il poss\u00e8de les caract\u00e9ristiques suivantes : CA 10 ; 1 point de vie ; Force 2 ; ne peut pas attaquer. Le sort se termine si le serviteur tombe \u00e0 0 point de vie.Une fois par tour, par une action bonus, vous pouvez mentalement ordonner au serviteur de se d\u00e9placer de 4,50 m\u00e8tres et d'interagir avec un objet. Le serviteur peut ex\u00e9cuter des t\u00e2ches simples comme un ser..."},
  "Silence": {desc: "Pour la dur\u00e9e du sort, aucun son ne peut \u00eatre cr\u00e9\u00e9 au sein (ou passer \u00e0 travers) d'une sph\u00e8re de 6 m\u00e8tres de rayon centr\u00e9e sur le point que vous choisissez dans la port\u00e9e du sort. Toute cr\u00e9ature ou objet se trouvant enti\u00e8rement \u00e0 l'int\u00e9rieur de la sph\u00e8re est immunis\u00e9 contre les d\u00e9g\u00e2ts de tonnerre et les cr\u00e9atures sont en plus assourdies.Lancer un sort qui comprend une composante verbale \u00e0 l'int\u00e9rieur de la sph\u00e8re est impossible."},
  "Soin des blessures": {desc: "Une cr\u00e9ature que vous touchez r\u00e9cup\u00e8re un nombre de points de vie \u00e9gal \u00e0 1d8 + le modificateur de votre caract\u00e9ristique d'incantation. Ce sort n'a pas d'effet sur les morts-vivants et les artificiels.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, la quantit\u00e9 de points de vie r\u00e9cup\u00e9r\u00e9s est augment\u00e9e de 1d8 pour chaque niveau d'emplacement au-del\u00e0 du niveau 1.", upcast_dice: "1d8", upcast_from: 1},
  "Sommeil": {desc: "Ce sort exp\u00e9die les cr\u00e9atures dans un sommeil magique. Lancez 5d8 ; le total est le nombre de points de vie des cr\u00e9atures que ce sort peut affecter. Les cr\u00e9atures \u00e0 6 m\u00e8tres ou moins du point que vous choisissez dans la port\u00e9e du sort sont affect\u00e9es par ordre croissant de leurs points de vie actuels (en ignorant les cr\u00e9atures inconscientes).En commen\u00e7ant par la cr\u00e9ature qui a le plus faible nombre de points de vie actuel, chaque cr\u00e9ature affect\u00e9e par ce sort tombe inconsciente jusqu'\u00e0 ce que le sort se termine, que la cr\u00e9ature endormie prenne des d\u00e9g\u00e2ts ou que quelqu'un utilise une action p...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, lancez 2d8 suppl\u00e9mentaires pour chaque niveau d'emplacement au-del\u00e0 du niveau 1.", upcast_dice: "2d8", upcast_from: 1},
  "Sort mineur de l'occulte": {desc: "Un rayon d'\u00e9nergie cr\u00e9pitante zigzague jusqu'\u00e0 une cr\u00e9ature \u00e0 port\u00e9e. Effectuez une attaque \u00e0 distance avec un sort contre la cible. En cas de r\u00e9ussite, la cible subit 1d10 d\u00e9g\u00e2ts de force.Ce sort cr\u00e9e plus d'un rayon lorsque vous montez en niveau : deux rayons au niveau 5, trois rayons au niveau 11, et quatre rayons au niveau 17. Vous pouvez diriger les rayons sur une cible unique et les r\u00e9partir entre diff\u00e9rentes cr\u00e9atures. Effectuez un jet d'attaque s\u00e9par\u00e9 pour chaque rayon."},
  "Sorts de soin de la blessure": {desc: "Une cr\u00e9ature que vous touchez r\u00e9cup\u00e8re un nombre de points de vie \u00e9gal \u00e0 1d8 + le modificateur de votre caract\u00e9ristique d'incantation. Ce sort n'a pas d'effet sur les morts-vivants et les artificiels.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, la quantit\u00e9 de points de vie r\u00e9cup\u00e9r\u00e9s est augment\u00e9e de 1d8 pour chaque niveau d'emplacement au-del\u00e0 du niveau 1.", upcast_dice: "1d8", upcast_from: 1},
  "Souffle du dragon": {desc: "Vous touchez une cr\u00e9ature consentante et lui donnez le pouvoir de cracher de l'\u00e9nergie magique de sa bouche, \u00e0 condition qu'elle en ait une. Choisissez l'un des types de d\u00e9g\u00e2ts suivants : acide, froid, feu, foudre ou poison. Jusqu'\u00e0 la fin du sort, la cr\u00e9ature peut utiliser une action pour expirer l'\u00e9nergie du type choisi dans un c\u00f4ne de 4,50 m\u00e8tres. Toutes les cr\u00e9atures dans cette zone doivent effectuer un jet de sauvegarde de Dext\u00e9rit\u00e9, subissant 3d6 d\u00e9g\u00e2ts du type choisi en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 3 ou sup\u00e9rieur, les d\u00e9g\u00e2ts augmentent de 1d6 pour chaque niveau d'emplacement au-del\u00e0 du niveau 2.", upcast_dice: "1d6", upcast_from: 2, save: "DEX"},
  "Sph\u00e8re de feu": {desc: "Une sph\u00e8re de feu d'un diam\u00e8tre de 1,50 m\u00e8tre apparait dans un espace inoccup\u00e9 de votre choix dans la port\u00e9e et pour la dur\u00e9e du sort. Toute cr\u00e9ature qui termine son tour \u00e0 1,50 m\u00e8tre ou moins de la sph\u00e8re doit effectuer un jet de sauvegarde de Dext\u00e9rit\u00e9, subissant 2d6 d\u00e9g\u00e2ts de feu en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite.Avec une action bonus, vous pouvez d\u00e9placer la sph\u00e8re jusqu'\u00e0 9 m\u00e8tres. Si la sph\u00e8re entre en collision avec une cr\u00e9ature, celle-ci doit faire un jet de sauvegarde contre les d\u00e9g\u00e2ts de la sph\u00e8re et elle arr\u00eate son mouvement pour ce tour.Lorsque vous d...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 3 ou sup\u00e9rieur, les d\u00e9g\u00e2ts sont augment\u00e9s de 1d6 pour chaque niveau d'emplacement au-del\u00e0 du niveau 2.", upcast_dice: "1d6", upcast_from: 2, save: "DEX"},
  "Suggestion": {desc: "Vous proposez un plan d'activit\u00e9 (limit\u00e9e \u00e0 une phrase ou deux) et influencez magiquement une cr\u00e9ature que vous pouvez voir dans la port\u00e9e du sort et qui peut vous entendre et vous comprendre. Les cr\u00e9atures qui ne peuvent pas \u00eatre charm\u00e9es sont \u00e0 l'abri de cet effet. La suggestion doit \u00eatre formul\u00e9e de mani\u00e8re que la r\u00e9alisation de l'action semble raisonnable. Demander \u00e0 la cr\u00e9ature de se poignarder, de s'empaler sur une lance, de s'immoler ou tout autre acte qui lui serait dommageable met un terme au sort.La cible doit faire un jet de sauvegarde de Sagesse. En cas d'\u00e9chec, elle poursuit le...", save: "WIS"},
  "Suggestion de groupe": {desc: "Vous proposez un plan d'activit\u00e9 (limit\u00e9e \u00e0 une phrase ou deux) et influencez magiquement jusqu'\u00e0 12 cr\u00e9atures que vous pouvez voir dans la port\u00e9e du sort et qui peuvent vous entendre et vous comprendre. Les cr\u00e9atures qui ne peuvent pas \u00eatre charm\u00e9es sont \u00e0 l'abri de cet effet. La suggestion doit \u00eatre formul\u00e9e de mani\u00e8re que la r\u00e9alisation de l'action semble raisonnable. Demander \u00e0 la cr\u00e9ature de se poignarder, de s'empaler sur une lance, de s'immoler ou tout autre acte qui lui serait dommageable met un terme au sort.Chacune des cibles doit faire un jet de sauvegarde de Sagesse. En cas d'\u00e9c...", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 7, la dur\u00e9e du sort augmente \u00e0 10 jours. Avec un emplacement de sort de niveau 8, la dur\u00e9e du sort augmente \u00e0 30 jours. Avec un emplacement de sort de niveau 9, la dur\u00e9e du sort augmente \u00e0 une ann\u00e9e plus un jour.", save: "WIS"},
  "Symbole": {desc: "Lorsque vous lancez ce sort, vous inscrivez un dangereux glyphe soit sur une surface (comme une table ou une portion de plancher ou de mur) ou \u00e0 l'int\u00e9rieur d'un objet qui peut \u00eatre ferm\u00e9 pour dissimuler le glyphe (comme un livre, un rouleau de parchemin ou un coffre). Si vous optez pour la surface, le glyphe peut couvrir une superficie de 3 m\u00e8tres de diam\u00e8tre maximum. Si vous choisissez un objet, cet objet doit rester en place ; si l'objet est d\u00e9plac\u00e9 \u00e0 plus de 3 m\u00e8tres de l'endroit o\u00f9 le sort a \u00e9t\u00e9 lanc\u00e9, le glyphe est bris\u00e9, et le sort prend fin sans s'\u00eatre d\u00e9clench\u00e9.Le glyphe est pratiq...", save: "CON"},
  "Temp\u00eate de gr\u00eale": {desc: "Une pluie de gr\u00eale dure comme la pierre tombe au sol dans un cylindre de 6 m\u00e8tres de rayon et de 12 m\u00e8tres de haut centr\u00e9 sur le point choisi \u00e0 l'int\u00e9rieur de la port\u00e9e du sort. Chaque cr\u00e9ature dans le cylindre doit faire un jet de sauvegarde de Dext\u00e9rit\u00e9. Une cr\u00e9ature subit 2d8 d\u00e9g\u00e2ts contondants et 4d6 d\u00e9g\u00e2ts de froid en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite.Les gr\u00ealons transforment la zone d'effet de la temp\u00eate en un terrain difficile jusqu'\u00e0 la fin de votre prochain tour.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 5 ou sup\u00e9rieur, les d\u00e9g\u00e2ts contondants augmentent de 1d8 pour chaque niveau d'emplacement au-del\u00e0 du niveau 4.", upcast_dice: "1d8", upcast_from: 4, save: "DEX"},
  "Temp\u00eate de neige": {desc: "Tant que le sort persiste, une pluie glac\u00e9e et de la neige tombent dans un cylindre de 6 m\u00e8tres de hauteur avec un rayon de 12 m\u00e8tres, centr\u00e9 sur un point d\u00e9termin\u00e9 dans la port\u00e9e du sort. La visibilit\u00e9 dans la zone est nulle et les flammes nues dans la zone sont \u00e9teintes.Le sol dans la zone est couvert de glace glissante, rendant le terrain difficile. Lorsqu'une cr\u00e9ature p\u00e9n\u00e8tre dans la zone du sort pour la premi\u00e8re fois d'un tour ou lorsqu'elle y d\u00e9bute son tour, elle doit r\u00e9ussir un jet de sauvegarde de Dext\u00e9rit\u00e9 ou tomber \u00e0 terre.Si une cr\u00e9ature commence son tour dans la zone d'effet du...", save: "DEX"},
  "Terrain hallucinatoire": {desc: "Vous faites en sorte qu'un terrain dans un cube de 45 m\u00e8tres d'ar\u00eate, \u00e0 port\u00e9e, paraisse (d'un point de vue auditif, olfactif et visuel) \u00eatre d'un autre type de terrain naturel. Ainsi, un terrain \u00e0 ciel ouvert ou une route peut ressembler \u00e0 un marais, une colline, une crevasse, ou n'importe quel autre terrain difficile ou insurmontable. Un \u00e9tang peut \u00eatre illusoirement converti en prairie d'herbe verte, un pr\u00e9cipice peut ressembler \u00e0 une pente douce, et un ravin rocailleux peut prendre l'allure d'une large route plate. Les structures manufactur\u00e9es, les \u00e9quipements et les cr\u00e9atures dans la z..."},
  "Texte illusoire": {desc: "Vous \u00e9crivez sur un parchemin, du papier, ou tout autre mat\u00e9riau adapt\u00e9 \u00e0 l'\u00e9criture, et l'impr\u00e9gnez d'une puissante illusion qui reste en place pour toute la dur\u00e9e du sort.Pour vous et pour toute cr\u00e9ature que vous avez d\u00e9sign\u00e9e lorsque vous avez lanc\u00e9 ce sort, l'\u00e9criture appara\u00eet normalement, trac\u00e9e de votre main, et transmet ce que vous souhaitiez communiquer lorsque vous avez lanc\u00e9 ce sort. Pour toutes les autres cr\u00e9atures, les \u00e9critures semblent \u00eatre r\u00e9dig\u00e9es dans un dialecte inconnu ou magique, ce qui les rend inintelligibles. Vous pouvez sinon faire en sorte que les \u00e9critures transmet..."},
  "Thaumaturgie": {desc: "Vous simulez une chose extraordinaire, un signe de puissance surnaturelle. Vous cr\u00e9ez un des effets magiques suivants dans la limite de port\u00e9e du sort :\u2022 Votre voix devient trois fois plus puissante que la normale pour 1 minute.\u2022 Vous fa\u00eetes vaciller des flammes, augmentez ou diminuez leur intensit\u00e9, ou bien encore vous changez leur couleur pendant 1 minute.\u2022 Vous causez des tremblements inoffensifs dans le sol pendant 1 minute.\u2022 Vous cr\u00e9ez un son instantan\u00e9 qui provient d'un point de votre choix dans la limite de port\u00e9e du sort, tel qu'un grondement de tonnerre, le cri d'un corbeau ou des ..."},
  "Toile d'araign\u00e9e": {desc: "Vous invoquez une masse de toiles d'araign\u00e9es \u00e9paisse et collante \u00e0 un point de votre choix dans la port\u00e9e du sort. Les toiles remplissent un cube de 6 m\u00e8tres d'ar\u00eate \u00e0 cet endroit pendant la dur\u00e9e du sort. Les toiles sont consid\u00e9r\u00e9es comme un terrain difficile et la visibilit\u00e9 y est r\u00e9duite.Si les toiles ne sont pas ancr\u00e9es entre deux masses solides (comme des murs ou des arbres) ou superpos\u00e9es \u00e0 partir du sol, d'un mur ou du plafond, la masse de toiles invoqu\u00e9e s'effondre sur elle-m\u00eame et le sort se termine au d\u00e9but de votre prochain tour. Les toiles superpos\u00e9es sur une surface plane ont ...", save: "DEX"},
  "Trait de feu": {desc: "Vous lancez un trait de feu sur une cr\u00e9ature ou un objet \u00e0 port\u00e9e. Faites une attaque \u00e0 distance avec un sort contre la cible. En cas de r\u00e9ussite, la cible prend 1d10 d\u00e9g\u00e2ts de feu. Un objet inflammable touch\u00e9 par ce sort prend feu s'il n'est pas port\u00e9.Les d\u00e9g\u00e2ts du sort augmentent de 1d10 aux niveaux 5 (2d10), 11 (3d10) et 17 (4d10)."},
  "Trait de givre": {desc: "Un faisceau glacial de lumi\u00e8re bleu\u00e2tre se dirige vers une cr\u00e9ature dans la port\u00e9e du sort. Effectuez une attaque \u00e0 distance avec un sort contre la cible. S'il touche, la cible subit 1d8 d\u00e9g\u00e2ts de froid et sa vitesse est r\u00e9duite de 3 m\u00e8tres jusqu'\u00e0 d\u00e9but de votre prochain tour.Les d\u00e9g\u00e2ts du sort augmentent de 1d8 lorsque vous atteignez le niveau 5 (2d8), le niveau 11 (3d8) et le niveau 17 (4d8)."},
  "T\u00e9l\u00e9kin\u00e9sie": {desc: "Vous obtenez la capacit\u00e9 de d\u00e9placer ou manipuler les cr\u00e9atures ou les objets par la pens\u00e9e. Lorsque vous lancez ce sort, et par une action \u00e0 chaque tour pour la dur\u00e9e du sort, vous pouvez user de votre volont\u00e9 sur une cr\u00e9ature ou un objet que vous pouvez voir et \u00e0 port\u00e9e, g\u00e9n\u00e9rant l'effet correspondant (voir ci-dessous). Vous pouvez affecter la m\u00eame cible tour apr\u00e8s tour, ou en choisir une nouvelle \u00e0 tout moment. Si vous changez de cible, la cible pr\u00e9c\u00e9dente n'est plus affect\u00e9e par le sort.Cr\u00e9ature. Vous pouvez essayer de d\u00e9placer une cr\u00e9ature de taille TG ou inf\u00e9rieure. Effectuez un jet d..."},
  "T\u00e9l\u00e9portation": {desc: "Ce sort vous transporte instantan\u00e9ment vous et jusqu'\u00e0 huit cr\u00e9atures consentantes de votre choix, ou un seul objet, \u00e0 condition dans les deux cas que vous puissiez les voir dans la limite de la port\u00e9e du sort, vers une destination que vous d\u00e9terminez. Si vous ciblez un objet, il doit \u00eatre possible de l'ins\u00e9rer enti\u00e8rement \u00e0 l'int\u00e9rieur d'un cube de 3 m\u00e8tres d'ar\u00eate et il ne peut \u00eatre tenu ou port\u00e9 par une cr\u00e9ature non-consentante.La destination que vous choisissez doit vous \u00eatre connue et doit \u00eatre sur le m\u00eame plan d'existence que vous. Votre connaissance de la destination d\u00e9termine si vou..."},
  "Vague tonnante": {desc: "Une vague de force de tonnerre \u00e9mane de vous. Toute cr\u00e9ature se trouvant dans un cube de 4,50 m\u00e8tres d'ar\u00eate prenant origine \u00e0 partir de vous-m\u00eame doit effectuer un jet de sauvegarde de Constitution. En cas d'\u00e9chec, la cr\u00e9ature subit 2d8 d\u00e9g\u00e2ts de tonnerre et est repouss\u00e9e de 3 m\u00e8tres de vous. En cas de r\u00e9ussite, elle subit la moiti\u00e9 de ces d\u00e9g\u00e2ts et n'est pas repouss\u00e9e.En outre, les objets non fix\u00e9s qui se trouvent enti\u00e8rement dans la zone d'effet sont automatiquement repouss\u00e9s de 3 m\u00e8tres par l'effet du sort, et le sort \u00e9met un coup de tonnerre audible jusqu'\u00e0 90 m\u00e8tres.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 2 ou sup\u00e9rieur, les d\u00e9g\u00e2ts augmentent de 1d8 pour chaque niveau d'emplacement au-del\u00e0 du niveau 1.", upcast_dice: "1d8", upcast_from: 1, save: "CON"},
  "Verrou magique": {desc: "Vous touchez un objet ferm\u00e9 comme une porte, une fen\u00eatre, un portail ou un coffre, et celui-ci se retrouve verrouill\u00e9 pour la dur\u00e9e du sort. Vous et les cr\u00e9atures que vous d\u00e9signez lors du lancement du sort pouvez ouvrir l'objet normalement. Vous pouvez aussi cr\u00e9er un mot de passe qui, quand il est prononc\u00e9 \u00e0 1,50 m\u00e8tre ou moins de l'objet, supprime l'effet du sort pendant 1 minute. Autrement, il est impossible d'ouvrir l'objet, sauf s'il est bris\u00e9 ou si le sort est dissip\u00e9 ou prend fin. Lancer le sort d\u00e9blocage supprime verrou magique pendant 10 minutes.L'objet affect\u00e9 par le sort est plus..."},
  "Vision dans le noir": {desc: "Vous touchez une cr\u00e9ature consentante pour lui conf\u00e9rer la capacit\u00e9 de voir dans le noir. Pour la dur\u00e9e du sort, cette cr\u00e9ature obtient la vision dans le noir (port\u00e9e 18 m\u00e8tres)."},
  "Vol": {desc: "Vous touchez une cr\u00e9ature consentante. La cible obtient une vitesse de vol de 18 m\u00e8tres pour la dur\u00e9e du sort. Lorsque le sort prend fin, la cible tombe si elle est toujours dans les airs, sauf si elle peut emp\u00eacher la chute.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 4 ou sup\u00e9rieur, vous pouvez cibler une cr\u00e9ature additionnelle pour chaque niveau d'emplacement au-del\u00e0 du niveau 3.", upcast_from: 3},
  "\u00c9clair": {desc: "Un rayon de foudre formant une ligne d'une longueur de 30 m\u00e8tres et d'une largeur de 1,50 m\u00e8tre jaillit de vous dans la direction de votre choix. Toute cr\u00e9ature sur la ligne doit effectuer un jet de sauvegarde de Dext\u00e9rit\u00e9, subissant 8d6 d\u00e9g\u00e2ts de foudre en cas d'\u00e9chec, ou la moiti\u00e9 de ces d\u00e9g\u00e2ts en cas de r\u00e9ussite.L'\u00e9clair enflamme les objets inflammables qui ne sont pas port\u00e9s ou transport\u00e9s.", upcast: "Aux niveaux sup\u00e9rieurs. Lorsque vous lancez ce sort en utilisant un emplacement de sort de niveau 4 ou sup\u00e9rieur, les d\u00e9g\u00e2ts augmentent de 1d6 pour chaque niveau d'emplacement au-del\u00e0 du niveau 3.", upcast_dice: "1d6", upcast_from: 3, save: "DEX"},
};